// ═══════════════════════════════════════════════════════════════
// §3  PERSISTENT STATE
// ═══════════════════════════════════════════════════════════════

function _ld(){ try{return JSON.parse(secureGet("nt_mn","{}","{}"));}catch(e){return {};} }
function _sv(s){ secureSet("nt_mn",JSON.stringify(s)); }
function _s(){
    const s=_ld();
    s.dd=s.dd||0; s.dl=s.dl||0; s.wl=s.wl||0; s.fl=s.fl||0;
    s.bo=s.bo||{}; s.bx=s.bx||0; s.bp=s.bp||false; s.bc=s.bc||{};
    s.sp=s.sp||false; s.gm=s.gm||0;
    s._socialDone=s._socialDone||{};
    return s;
}

// Booster helpers
function _isB(id){ const s=_s(),b=s.bo[id]; if(!b) return false; const d=BOOSTS.find(x=>x.id===id); if(!d) return false; return d.dur===0?(b.u||0)>0:(Date.now()-b.a)<d.dur; }
function _actB(id){ const s=_s(),d=BOOSTS.find(x=>x.id===id); if(!d) return; if(d.dur===0){if(!s.bo[id])s.bo[id]={u:0};s.bo[id].u=(s.bo[id].u||0)+1;}else{s.bo[id]={a:Date.now()};} _sv(s); }
function _useB(id){ const s=_s(); if(s.bo[id]&&(s.bo[id].u||0)>0){s.bo[id].u--;_sv(s);return true;} return false; }
function _gMult(){ return _isB("gold2x")?2.0:1.0; }
function _xMult(){ return _isB("xp2x")?2.0:1.0; }

// Time helpers
function _sameDay(a,b){ return new Date(a).toDateString()===new Date(b).toDateString(); }
function _nextDay(a,b){ const d1=new Date(a);d1.setHours(0,0,0,0);const d2=new Date(b);d2.setHours(0,0,0,0);const x=d2-d1;return x>=864e5&&x<1728e5; }
function _fmt(ms){ const h=Math.floor(ms/36e5),m=Math.floor((ms%36e5)/6e4),s=Math.floor((ms%6e4)/1e3); return (h?h+"h ":"")+m+"m "+s+"s"; }
function _rlbl(r){ return r.type==="gold"?r.n+(CURRENT_LANG==="tr"?" ALTIN":" GOLD"):r.n+(CURRENT_LANG==="tr"?" NF Elmas":" NF GEM"); }


// ═══════════════════════════════════════════════════════════════
// §4  DAILY REWARDS  (only CLAIM, no close, auto-dismiss)
// ═══════════════════════════════════════════════════════════════

function _dailyOK(){ const s=_s(); if(!s.dl) return true; if(s.dd>=7&&_sameDay(s.dl,Date.now())) return false; return !_sameDay(s.dl,Date.now()); }
function checkDaily(sc){ if(_dailyOK()) sc.time.delayedCall(600,()=>showDaily(sc)); }

function showDaily(scene){
    const {A,close,contentTop,contentBot,CX:cx,depth:D,objs}
        = NT_OpenPopup(scene,"mm_panel",300,CURRENT_LANG==="tr"?"GUNLUK ODUL":"DAILY REWARD",320,20,null);

    // Remove the default close button (last 3 objects added by NT_OpenPopup: graphics, text, hitRect)
    // Pop them from objs and destroy
    for(let i=0;i<3;i++){
        const o = objs.pop();
        try{ if(o.disableInteractive) o.disableInteractive(); o.destroy(); }catch(_){}
    }

    const s=_s();
    let cur=s.dd||0;
    if(s.dl>0&&!_nextDay(s.dl,Date.now())&&!_sameDay(s.dl,Date.now())) cur=0;
    if(cur>=7) cur=0;

    // Streak text
    A(scene.add.text(cx,contentTop+8,(CURRENT_LANG==="tr"?"GUN ":"DAY ")+(cur+1)+(CURRENT_LANG==="tr"?" / 7":" OF 7"),{fontFamily:_F,fontSize:"12px",color:"#ffdd44",stroke:"#000",strokeThickness:2}).setOrigin(0.5).setDepth(D+3));

    // Mizah alt yazisi — panelin icinde, streak altinda
    A(scene.add.text(cx,contentTop+22,CURRENT_LANG==="tr"?"NOT bedava degil.":"NOThing is for free.",{fontFamily:_F,fontSize:"8px",color:"#ff8844",stroke:"#000",strokeThickness:1}).setOrigin(0.5).setDepth(D+3));

    // ── PREMIUM 7-DAY REWARD CARDS ──────────────────────────────
    const CW=62, CH=72, G=4;
    const rows=[[0,1,2,3],[4,5,6]];
    const bY=contentTop+40;

    rows.forEach((row,ri)=>{
        const rw=row.length*CW+(row.length-1)*G;
        const sx=cx-rw/2+CW/2;
        row.forEach((idx,ci)=>{
            const cardX=sx+ci*(CW+G), cardY=bY+ri*(CH+G)+CH/2;
            const reward=DAILY[idx];
            const claimed=idx<cur, current=idx===cur, locked=idx>cur;
            const isGem=reward.type==="gem";
            const _icKey=isGem?"icon_gem":"icon_gold";

            // Collect card objects for stagger (excluding glow which self-manages alpha)
            const _cObjs=[];
            const CA=(o)=>{ A(o); _cObjs.push(o); return o; };

            // ── DROP SHADOW ──
            const sh=CA(scene.add.graphics().setDepth(D+1));
            sh.fillStyle(0x000000,0.55);
            sh.fillRoundedRect(cardX-CW/2+2,cardY-CH/2+4,CW,CH,9);

            // ── CARD BASE ──
            const cg=CA(scene.add.graphics().setDepth(D+2));

            if(claimed){
                // Deep forest green base
                cg.fillStyle(0x081a10,1);
                cg.fillRoundedRect(cardX-CW/2,cardY-CH/2,CW,CH,8);
                // Top accent bar — rich green
                cg.fillStyle(0x0d4020,1);
                cg.fillRoundedRect(cardX-CW/2,cardY-CH/2,CW,20,{tl:8,tr:8,bl:0,br:0});
                // Border — vivid green
                cg.lineStyle(2,0x33dd66,0.85);
                cg.strokeRoundedRect(cardX-CW/2,cardY-CH/2,CW,CH,8);
                // Inner top gloss
                cg.fillStyle(0xffffff,0.05);
                cg.fillRoundedRect(cardX-CW/2+2,cardY-CH/2+2,CW-4,28,{tl:6,tr:6,bl:0,br:0});

            } else if(current){
                // Warm amber base
                cg.fillStyle(0x140a00,1);
                cg.fillRoundedRect(cardX-CW/2,cardY-CH/2,CW,CH,8);
                // Top accent bar — rich amber
                cg.fillStyle(0x3a1e00,1);
                cg.fillRoundedRect(cardX-CW/2,cardY-CH/2,CW,20,{tl:8,tr:8,bl:0,br:0});
                // Thick gold border
                cg.lineStyle(2.5,0xffaa00,1);
                cg.strokeRoundedRect(cardX-CW/2,cardY-CH/2,CW,CH,8);
                // Inner gloss
                cg.fillStyle(0xffffff,0.06);
                cg.fillRoundedRect(cardX-CW/2+2,cardY-CH/2+2,CW-4,28,{tl:6,tr:6,bl:0,br:0});

            } else {
                // Dark navy base — locked
                cg.fillStyle(0x070b16,1);
                cg.fillRoundedRect(cardX-CW/2,cardY-CH/2,CW,CH,8);
                // Top accent bar — muted blue
                cg.fillStyle(0x0c1530,1);
                cg.fillRoundedRect(cardX-CW/2,cardY-CH/2,CW,20,{tl:8,tr:8,bl:0,br:0});
                // Subtle border
                cg.lineStyle(1.5,0x2255aa,0.35);
                cg.strokeRoundedRect(cardX-CW/2,cardY-CH/2,CW,CH,8);
                // Dark overlay for locked feel
                cg.fillStyle(0x000000,0.35);
                cg.fillRoundedRect(cardX-CW/2,cardY-CH/2,CW,CH,8);
            }

            // ── DAY LABEL ──
            const _dayCol = claimed?"#55ee88" : current?"#ffcc33" : "#334466";
            CA(scene.add.text(cardX, cardY-CH/2+10,
                (CURRENT_LANG==="tr"?"G":"D")+(idx+1),
                {fontFamily:_F,fontSize:"9px",color:_dayCol,
                 stroke:"#000000",strokeThickness:2}
            ).setOrigin(0.5).setDepth(D+3));

            // ── STATE CONTENT ──
            if(claimed){
                // Premium checkmark — drawn with graphics, NO thin Unicode tick
                const ck=CA(scene.add.graphics().setDepth(D+4));
                const ckX=cardX, ckY=cardY+6;
                const cR=13;
                // Outer glow ring
                ck.lineStyle(4,0x22cc55,0.25);
                ck.strokeCircle(ckX,ckY,cR+4);
                // Filled green circle
                ck.fillStyle(0x18993a,1);
                ck.fillCircle(ckX,ckY,cR);
                // Top gloss on circle
                ck.fillStyle(0xffffff,0.18);
                ck.fillCircle(ckX-1,ckY-3,cR-4);
                // Bold white checkmark strokes (thick, not thin)
                ck.lineStyle(3.5,0xffffff,1);
                ck.beginPath();
                ck.moveTo(ckX-7, ckY+1);
                ck.lineTo(ckX-1, ckY+7);
                ck.lineTo(ckX+9, ckY-7);
                ck.strokePath();
                // "CLAIMED" label below
                CA(scene.add.text(cardX, cardY+cR+14, "CLAIMED",
                    {fontFamily:_F,fontSize:"6px",color:"#44cc66",stroke:"#000",strokeThickness:1}
                ).setOrigin(0.5).setDepth(D+4));

            } else if(current){
                // Big reward amount — white, bold
                const amtStr="+"+reward.amount;
                CA(scene.add.text(cardX, cardY+2, amtStr,
                    {fontFamily:_F,fontSize:"17px",color:"#ffffff",
                     stroke:"#000000",strokeThickness:3}
                ).setOrigin(0.5).setDepth(D+3));
                // Icon below amount — sayiyla orantili boyut
                if(scene.textures.exists(_icKey)){
                    CA(scene.add.image(cardX, cardY+22, _icKey)
                        .setDisplaySize(20,20).setOrigin(0.5).setDepth(D+3));
                }

            } else {
                // Locked — dimmed reward preview
                const amtStr="+"+reward.amount;
                CA(scene.add.text(cardX, cardY+2, amtStr,
                    {fontFamily:_F,fontSize:"13px",color:"#2c3d55",
                     stroke:"#000000",strokeThickness:2}
                ).setOrigin(0.5).setDepth(D+3));
                if(scene.textures.exists(_icKey)){
                    CA(scene.add.image(cardX, cardY+20, _icKey)
                        .setDisplaySize(15,15).setOrigin(0.5).setDepth(D+3).setAlpha(0.22));
                }
            }

            // ── CURRENT DAY GLOW PULSE ──
            if(current){
                const gl=A(scene.add.graphics().setDepth(D+1));
                const gv={v:0};
                scene.tweens.add({targets:gv,v:1,duration:850,yoyo:true,repeat:-1,ease:"Sine.easeInOut",
                    onUpdate:()=>{
                        if(!gl.scene) return; gl.clear();
                        gl.lineStyle(4+gv.v*7,0xffaa00,0.04+gv.v*0.22);
                        gl.strokeRoundedRect(cardX-CW/2-5,cardY-CH/2-5,CW+10,CH+10,13);
                    }
                });
            }

            // ── STAGGER FADE IN (all card objects) ──
            _cObjs.forEach(o=>{ try{o.setAlpha(0);}catch(_){} });
            scene.tweens.add({targets:_cObjs,alpha:1,duration:240,delay:60+idx*55,ease:"Quad.easeOut"});
        });
    });

    // ── CLAIM BUTTON ──
    const claimY = contentBot - 20;
    const reward = DAILY[cur];
    const [cbg,cbt,cbh] = NT_YellowBtn(scene,cx,claimY,200,44,(CURRENT_LANG==="tr"?"AL  ✦":"CLAIM  ✦"),D+3,()=>{
        // Save state
        const st=_s();
        if(st.dl>0&&!_nextDay(st.dl,Date.now())&&!_sameDay(st.dl,Date.now())) st.dd=0;
        st.dd=cur+1; st.dl=Date.now(); if(st.dd>=7) st.dd=7; _sv(st);

        // Give reward + BIG animation
        NT_SFX.play("chest_open","common");
        showBigReward(scene, cx, claimY-30, reward.type, reward.amount, D+10);

        // Auto-dismiss after animation
        scene.time.delayedCall(350, close);
    });
    A(cbg);A(cbt);A(cbh);
}


// ═══════════════════════════════════════════════════════════════
// §5  FORTUNE WHEEL  (smooth spin, exact rewards, big popup)
// ═══════════════════════════════════════════════════════════════

function _canFree(){ return (Date.now()-_s().wl)>=WHEEL_FREE_CD; }
function _freeT(){ const e=Date.now()-_s().wl; return e>=WHEEL_FREE_CD?0:WHEEL_FREE_CD-e; }

function showWheel(scene){
    const D=500;
    const objs=[],A=o=>{objs.push(o);return o;};
    // Hide HTML avatar overlay — sits on top of Phaser canvas
    if(scene._tgAvatarHtmlEl) try{ scene._tgAvatarHtmlEl.style.transition='none'; scene._tgAvatarHtmlEl.style.opacity='0'; scene._tgAvatarHtmlEl.style.pointerEvents='none'; }catch(_){}
    const _close=()=>{
        if(_wheelListener)scene.input.off("wheel",_wheelListener);
        objs.forEach(o=>{try{o.destroy();}catch(_){}});
        if(scene._tgAvatarHtmlEl) try{ scene._tgAvatarHtmlEl.style.transition='opacity 0.3s ease'; scene._tgAvatarHtmlEl.style.opacity='1'; scene._tgAvatarHtmlEl.style.pointerEvents='none'; }catch(_){}
    };
    let spinning=false;
    let _wheelListener=null;

    // Overlay
    A(scene.add.rectangle(CX,H/2,W,H,0x000000,0.88).setDepth(D).setInteractive());

    // Title with glow
    const titleGlow=A(scene.add.text(CX,22,CURRENT_LANG==="tr"?"ŞANS ÇARKI":"FORTUNE WHEEL",{fontFamily:_F,fontSize:"28px",color:"#ffffff",stroke:"#1a0800",strokeThickness:6}).setOrigin(0.5).setDepth(D+2).setResolution(2));
    A(scene.add.text(CX,46,CURRENT_LANG==="tr"?"NOT garantisi vermiyoruz.":"NOThing guaranteed.",{fontFamily:_F,fontSize:"14px",color:"#aabbcc",stroke:"#000",strokeThickness:3}).setOrigin(0.5).setDepth(D+2));
    const tgv={v:0};
    A({destroy:()=>{},scene:scene});
    scene.tweens.add({targets:tgv,v:1,duration:1500,yoyo:true,repeat:-1,ease:"Sine.easeInOut",
        onUpdate:()=>{if(!titleGlow.scene)return;titleGlow.setAlpha(0.85+tgv.v*0.15);}});

    // Voice line — wheel paneli açılır açılmaz
    scene.time.delayedCall(80, ()=>{ if(typeof NT_VL!=="undefined") NT_VL.playWheelVoice(scene); });

    // ── WHEEL CONFIG ──
    const R=140, WY=235, SC=WHEEL.length, SA=Math.PI*2/SC;
    let wAngle=0;

    // ── Draw custom wheel graphic ──
    const wheelGfx=A(scene.add.graphics().setDepth(D+2));
    wheelGfx.x=CX; wheelGfx.y=WY;

    // Sector colors — dark professional theme (red/blue/grey tones)
    const sectorColors=[
        0x1c2a4a, 0x7a0c0c, 0x0e1c3a, 0x5a0808,
        0x162238, 0x6e1212, 0x0a1628, 0x3a1010,
        0x1a2e50, 0x880e0e
    ];

    function _drawWheel(angle){
        wheelGfx.clear();
        wheelGfx.setRotation(angle);

        // Deep outer shadow
        wheelGfx.fillStyle(0x000000, 0.55);
        wheelGfx.fillCircle(4, 5, R+14);

        // Outermost dark band
        wheelGfx.fillStyle(0x080c14, 1);
        wheelGfx.fillCircle(0, 0, R+12);

        // Gold accent ring
        wheelGfx.lineStyle(5, 0xddaa00, 1);
        wheelGfx.strokeCircle(0, 0, R+8);
        wheelGfx.lineStyle(1.5, 0xffeebb, 0.55);
        wheelGfx.strokeCircle(0, 0, R+10);

        // Separator ring before sectors
        wheelGfx.lineStyle(2, 0x000000, 0.85);
        wheelGfx.strokeCircle(0, 0, R+1);

        // Draw sectors
        for(let i=0;i<SC;i++){
            const startA = i*SA - Math.PI/2;
            const endA = startA + SA;
            const col = sectorColors[i % sectorColors.length];
            const midA = startA + SA/2;

            // Filled sector
            wheelGfx.fillStyle(col, 1);
            wheelGfx.beginPath();
            wheelGfx.moveTo(0, 0);
            wheelGfx.arc(0, 0, R, startA, endA, false);
            wheelGfx.closePath();
            wheelGfx.fillPath();

            // Outer glow strip on each sector
            wheelGfx.fillStyle(0xffffff, 0.06);
            wheelGfx.beginPath();
            wheelGfx.arc(0, 0, R, startA, endA, false);
            wheelGfx.arc(0, 0, R*0.78, endA, startA, true);
            wheelGfx.closePath();
            wheelGfx.fillPath();

            // Sector divider lines
            wheelGfx.lineStyle(2, 0x000000, 0.90);
            wheelGfx.beginPath();
            wheelGfx.moveTo(0, 0);
            wheelGfx.lineTo(Math.cos(startA)*(R+1), Math.sin(startA)*(R+1));
            wheelGfx.strokePath();
            wheelGfx.lineStyle(1, 0xffffff, 0.10);
            wheelGfx.beginPath();
            wheelGfx.moveTo(Math.cos(startA)*18, Math.sin(startA)*18);
            wheelGfx.lineTo(Math.cos(startA)*(R+1), Math.sin(startA)*(R+1));
            wheelGfx.strokePath();
        }

        // Inner circle — clean ring
        wheelGfx.lineStyle(2, 0x000000, 0.70);
        wheelGfx.strokeCircle(0, 0, R*0.30);

        // Center hub shadow
        wheelGfx.fillStyle(0x000000, 0.60);
        wheelGfx.fillCircle(2, 3, 26);
        // Center hub — dark metallic
        wheelGfx.fillStyle(0x141820, 1);
        wheelGfx.fillCircle(0, 0, 24);
        // Hub gold rim
        wheelGfx.lineStyle(3, 0xddaa00, 1);
        wheelGfx.strokeCircle(0, 0, 24);
        wheelGfx.lineStyle(1, 0xffeebb, 0.40);
        wheelGfx.strokeCircle(0, 0, 22);
        // Inner hub detail
        wheelGfx.fillStyle(0x0c1020, 1);
        wheelGfx.fillCircle(0, 0, 16);
        wheelGfx.lineStyle(1.5, 0x4466aa, 0.55);
        wheelGfx.strokeCircle(0, 0, 16);
        // Center dot
        wheelGfx.fillStyle(0xddaa00, 0.85);
        wheelGfx.fillCircle(0, 0, 5);
        wheelGfx.fillStyle(0xffeebb, 0.6);
        wheelGfx.fillCircle(0, 0, 2);

        // Rim decorative dots — evenly spaced at sector boundaries
        for(let i=0;i<SC;i++){
            const da = i*SA - Math.PI/2;
            const dx = Math.cos(da)*(R+8);
            const dy = Math.sin(da)*(R+8);
            wheelGfx.fillStyle(0xddaa00, 1);
            wheelGfx.fillCircle(dx, dy, 4);
            wheelGfx.fillStyle(0xffeebb, 0.7);
            wheelGfx.fillCircle(dx, dy, 2);
        }
    }
    _drawWheel(0);

    // ── Slice labels (rotate with wheel) ──
    // Layout: icon at R*0.76 (outer), number at R*0.46 (inner) — clear separation
    const lbls=[];
    const sliceIcons=[];
    const _LBL_R  = R * 0.50;  // number label radius
    const _ICO_R  = R * 0.80;  // icon radius (near rim)
    const _ICO_SZ = 28;        // icon display size
    for(let i=0;i<SC;i++){
        const mid=i*SA+SA/2-Math.PI/2;
        const sl=WHEEL[i];
        const isGld=sl.type==="gold";
        const lbl=String(sl.amount);
        const col=isGld?"#ffe066":"#ffccff";
        // Number label — positioned in inner zone
        const t=A(scene.add.text(
            CX+Math.cos(mid)*_LBL_R,
            WY+Math.sin(mid)*_LBL_R,
            lbl,
            {fontFamily:_F,fontSize:"15px",color:col,stroke:"#000000",strokeThickness:5,align:"center"}
        ).setOrigin(0.5).setDepth(D+3).setRotation(mid+Math.PI/2).setResolution(2));
        lbls.push(t);
        // Icon — positioned near outer rim
        const icKey=isGld?"icon_gold":"icon_gem";
        const icArr=[];
        if(scene.textures.exists(icKey)){
            const ic=A(scene.add.image(
                CX+Math.cos(mid)*_ICO_R,
                WY+Math.sin(mid)*_ICO_R,
                icKey
            ).setDisplaySize(_ICO_SZ,_ICO_SZ).setDepth(D+4).setRotation(mid+Math.PI/2));
            icArr.push({img:ic,offsetAngle:0});
        }
        sliceIcons.push(icArr);
    }
    function _uL(a){
        for(let i=0;i<SC;i++){
            const mid=a+i*SA+SA/2-Math.PI/2;
            lbls[i].setPosition(CX+Math.cos(mid)*_LBL_R,WY+Math.sin(mid)*_LBL_R).setRotation(mid+Math.PI/2);
            const icons=sliceIcons[i];
            for(let j=0;j<icons.length;j++){
                const ic=icons[j];
                const icAngle=mid+ic.offsetAngle;
                ic.img.setPosition(CX+Math.cos(icAngle)*_ICO_R,WY+Math.sin(icAngle)*_ICO_R).setRotation(icAngle+Math.PI/2);
            }
        }
    }

    // ── Arrow pointer — premium 3D look ──
    const ar=A(scene.add.graphics().setDepth(D+6));
    const _arTX=CX, _arTY=WY-R-4;
    const _arHH=34, _arHW=18;
    // Outer shadow
    ar.fillStyle(0x000000,0.50);
    ar.fillTriangle(_arTX+3,_arTY+4, _arTX-_arHW+2,_arTY-_arHH, _arTX+_arHW+2,_arTY-_arHH);
    // Dark outline
    ar.fillStyle(0x1a0000,1);
    ar.fillTriangle(_arTX,_arTY+2, _arTX-_arHW-1,_arTY-_arHH-2, _arTX+_arHW+1,_arTY-_arHH-2);
    // Main arrow body
    ar.fillStyle(0xcc1122,1);
    ar.fillTriangle(_arTX,_arTY, _arTX-_arHW,_arTY-_arHH, _arTX+_arHW,_arTY-_arHH);
    // Mid highlight stripe
    ar.fillStyle(0xff4455,0.70);
    ar.fillTriangle(_arTX,_arTY-6, _arTX-_arHW+6,_arTY-_arHH, _arTX+_arHW-6,_arTY-_arHH);
    // Top bright edge
    ar.lineStyle(2,0xff7788,0.60);
    ar.lineBetween(_arTX-_arHW,_arTY-_arHH,_arTX+_arHW,_arTY-_arHH);
    // White rim
    ar.lineStyle(1.5,0xffffff,0.30);
    ar.lineBetween(_arTX,_arTY,_arTX-_arHW,_arTY-_arHH);
    ar.lineBetween(_arTX,_arTY,_arTX+_arHW,_arTY-_arHH);
    // Anchor circle at tip
    ar.fillStyle(0x880011,1);ar.fillCircle(_arTX,_arTY,6);
    ar.fillStyle(0xcc1122,1);ar.fillCircle(_arTX,_arTY,4);
    ar.fillStyle(0xffffff,0.55);ar.fillCircle(_arTX,_arTY,2);

    // ── Outer glow ring animation ──
    const glowRing=A(scene.add.graphics().setDepth(D+1));
    const grv={v:0};
    scene.tweens.add({targets:grv,v:1,duration:2000,yoyo:true,repeat:-1,ease:"Sine.easeInOut",
        onUpdate:()=>{
            if(!glowRing.scene)return;
            glowRing.clear();
            glowRing.lineStyle(4+grv.v*6,0xffcc00,0.05+grv.v*0.12);
            glowRing.strokeCircle(CX,WY,R+14+grv.v*8);
        }
    });

    // Timer display
    const cf=_canFree();
    if(!cf){
        const tt=A(scene.add.text(CX,WY+R+26,"",{fontFamily:_F,fontSize:"12px",color:"#ff8844",stroke:"#000",strokeThickness:2}).setOrigin(0.5).setDepth(D+3));
        const te=scene.time.addEvent({delay:500,loop:true,callback:()=>{
            if(!tt.scene){te.remove();return;}
            const r=_freeT(); if(r<=0){tt.setText(CURRENT_LANG==="tr"?"BEDAVA ÇEVİRME HAZIR — NOT şaka!":"FREE SPIN — NOT a trick. Ready!").setColor("#44ff66");te.remove();return;}
            tt.setText((CURRENT_LANG==="tr"?"Sonraki ucretsiz: ":"Next free: ")+_fmt(r));
        }});
        te.callback();
        objs.push({destroy:()=>te.remove(),scene:scene});
    }

    // ── FREE SPIN button ──
    const fY=WY+R+52;
    const fBg=A(scene.add.graphics().setDepth(D+3));
    const _dF=h=>{fBg.clear();const c=cf?(h?0x228840:0x116630):0x333333;fBg.fillStyle(0x000000,0.35);fBg.fillRoundedRect(CX-108+2,fY-16+2,216,34,10);fBg.fillStyle(c,1);fBg.fillRoundedRect(CX-108,fY-16,216,34,10);fBg.lineStyle(2,cf?0x44ff66:0x555555,0.8);fBg.strokeRoundedRect(CX-108,fY-16,216,34,10);if(cf&&h){fBg.fillStyle(0xffffff,0.08);fBg.fillRoundedRect(CX-106,fY-14,212,12,{tl:8,tr:8,bl:0,br:0});}};
    _dF(false);
    // [FIX] Free spin text ref sakla — spin başlayınca WAITING'e çevirmek için
    const fTxt=A(scene.add.text(CX,fY,cf?(CURRENT_LANG==="tr"?"✦  UCRETSIZ CEVIR  ✦":"✦  FREE SPIN  ✦"):(CURRENT_LANG==="tr"?"NOT henüz...":"NOT yet."),{fontFamily:_F,fontSize:"16px",color:cf?"#ffffff":"#777777",stroke:"#000",strokeThickness:3}).setOrigin(0.5).setDepth(D+4));
    A(scene.add.rectangle(CX,fY,216,34,0xffffff,0.001).setDepth(D+5).setInteractive({useHandCursor:cf}))
    .on("pointerover",()=>{if(cf&&!spinning)_dF(true);}).on("pointerout",()=>_dF(false))
    .on("pointerdown",()=>{
        if(!_canFree()||spinning)return;
        // [FIX] Anında WAITING durumuna geç — spin başladı
        if(fTxt&&fTxt.active) fTxt.setText(CURRENT_LANG==="tr"?"NOT henüz...":"NOT yet.").setColor("#777777");
        _dF(false);
        _spin(true);
    });

    // ── GEM SPIN button ──
    const gY=fY+44;
    const gBg=A(scene.add.graphics().setDepth(D+3));
    const _dG=h=>{gBg.clear();gBg.fillStyle(0x000000,0.35);gBg.fillRoundedRect(CX-108+2,gY-16+2,216,34,10);gBg.fillStyle(h?0x5020aa:0x380068,1);gBg.fillRoundedRect(CX-108,gY-16,216,34,10);gBg.lineStyle(2,0xbb44ff,0.8);gBg.strokeRoundedRect(CX-108,gY-16,216,34,10);if(h){gBg.fillStyle(0xffffff,0.08);gBg.fillRoundedRect(CX-106,gY-14,212,12,{tl:8,tr:8,bl:0,br:0});}};
    _dG(false);
    // Width-based centering: [gem_icon][gap][cost text SPIN] group centered at CX
    const _spinLabel=WHEEL_COST+"  "+(CURRENT_LANG==="tr"?"CEVİR":"SPIN");
    const gemCostTxt=A(scene.add.text(0,gY,_spinLabel,{fontFamily:_F,fontSize:"15px",color:"#dd88ff",stroke:"#000",strokeThickness:2}).setOrigin(0,0.5).setDepth(D+4));
    const _gemSz=22,_gemGap=6;
    const _hasGemIc=scene.textures.exists("icon_gem");
    const _spinTotalW=(_hasGemIc?(_gemSz+_gemGap):0)+gemCostTxt.width;
    const _spinLeft=CX-_spinTotalW/2;
    gemCostTxt.x=_spinLeft+(_hasGemIc?(_gemSz+_gemGap):0);
    if(_hasGemIc){A(scene.add.image(_spinLeft+_gemSz/2,gY,"icon_gem").setDisplaySize(_gemSz,_gemSz).setOrigin(0.5).setDepth(D+4));}
    A(scene.add.rectangle(CX,gY,216,34,0xffffff,0.001).setDepth(D+5).setInteractive({useHandCursor:true}))
    .on("pointerover",()=>_dG(true)).on("pointerout",()=>_dG(false))
    .on("pointerdown",()=>{if(spinning)return;if(PLAYER_GEMS<WHEEL_COST){scene.cameras.main.shake(30,0.006);return;}spendGems(WHEEL_COST);_spin(false);});

    // Close
    const [xb,xt,xh]=NT_YellowBtn(scene,CX,H-32,150,36,CURRENT_LANG==="tr"?"KAPAT":"CLOSE",D+3,_close);
    A(xb);A(xt);A(xh);

    // ── TICK SOUND simulation — arrow bounce ──
    let _lastTickIdx=-1;
    const _arOrigY = 0; // ar is a graphics object at y=0

    // ── SPIN LOGIC — slow, dramatic, satisfying ──
    function _spin(isFree){
        if(spinning) return; spinning=true; NT_SFX.play("menu_click");
        _lastTickIdx=-1;
        // Reset arrow position in case previous bounce left it offset
        ar.y = _arOrigY;
        // Weighted random
        const tw=WHEEL.reduce((s,x)=>s+x.w,0); let rn=Math.random()*tw, wi=0;
        for(let i=0;i<SC;i++){rn-=WHEEL[i].w;if(rn<=0){wi=i;break;}}
        // Target angle: must land sector wi under the arrow (top)
        // Sector wi center in local coords = wi*SA + SA/2 - PI/2
        // After rotation by finalAngle, it should point at -PI/2 (top)
        // So: finalAngle = -(wi*SA + SA/2) + 2*PI*n
        const extraSpins = 8 + Math.random()*4;
        const landAngle = -(wi*SA + SA/2);
        const randomWithinSector = Math.random()*SA*0.3 - SA*0.15; // small offset within sector
        const finalTarget = landAngle + Math.PI*2*Math.ceil(extraSpins) + randomWithinSector;
        const sp={a:wAngle};
        const spinDuration = 6000 + Math.random()*2000; // 6-8 seconds
        scene.tweens.add({
            targets:sp, a:finalTarget, duration:spinDuration, ease:"Cubic.easeOut",
            onUpdate:()=>{
                _drawWheel(sp.a);
                _uL(sp.a);
                // Tick detection: which sector is at the top?
                const normA = ((sp.a % (Math.PI*2)) + Math.PI*2) % (Math.PI*2);
                const tickIdx = Math.floor(((Math.PI*2 - normA + Math.PI/2) % (Math.PI*2)) / SA) % SC;
                if(tickIdx !== _lastTickIdx){
                    _lastTickIdx = tickIdx;
                    NT_SFX.play("menu_click");
                    // Arrow bounce — always from original position
                    if(ar.scene){
                        ar.y = _arOrigY;
                        scene.tweens.add({targets:ar, y:_arOrigY-5, duration:50, yoyo:true, ease:"Quad.easeOut",
                            onComplete:()=>{ if(ar.scene) ar.y = _arOrigY; }
                        });
                    }
                }
            },
            onComplete:()=>{
                wAngle=sp.a%(Math.PI*2); spinning=false;
                ar.y = _arOrigY; // ensure arrow is reset
                const prize=WHEEL[wi];
                if(isFree){const st=_s();st.wl=Date.now();_sv(st);}
                // ── WIN CELEBRATION ──────────────────────────────────────
                NT_SFX.play("menu_click");
                scene.cameras.main.shake(350, 0.007);
                // Full-screen flash
                const winFlash=scene.add.graphics().setDepth(D+20);
                winFlash.fillStyle(prize.color||0xffcc00, 0.45);
                winFlash.fillRect(0,0,W,H);
                scene.tweens.add({targets:winFlash,alpha:0,duration:700,onComplete:()=>winFlash.destroy()});
                // Secondary pulse flash
                scene.time.delayedCall(180,()=>{
                    const wf2=scene.add.graphics().setDepth(D+20);
                    wf2.fillStyle(0xffffff,0.18); wf2.fillRect(0,0,W,H);
                    scene.tweens.add({targets:wf2,alpha:0,duration:350,onComplete:()=>wf2.destroy()});
                });
                // Particle burst from wheel center
                const _pCols=[prize.color||0xffcc00,0xffffff,0xffee44,0xff9900];
                for(let _pi=0;_pi<24;_pi++){
                    const _pg=scene.add.graphics().setDepth(D+22);
                    _pg.fillStyle(_pCols[_pi%_pCols.length],1);
                    const _pSz=2+Math.random()*5;
                    _pg.fillCircle(0,0,_pSz);
                    _pg.x=CX; _pg.y=WY;
                    const _ang=(Math.PI*2/24)*_pi;
                    const _dist=70+Math.random()*110;
                    scene.tweens.add({targets:_pg,x:CX+Math.cos(_ang)*_dist,y:WY+Math.sin(_ang)*_dist,alpha:0,duration:600+Math.random()*350,ease:"Quad.easeOut",onComplete:()=>_pg.destroy()});
                }
                // Confetti rain from top
                const _cfCols=[prize.color||0xffcc00,0xffffff,0xff4444,0x44ff88,0x44aaff,0xffee44];
                for(let _ci=0;_ci<22;_ci++){
                    const _cg=scene.add.graphics().setDepth(D+21);
                    _cg.fillStyle(_cfCols[_ci%_cfCols.length],1);
                    _cg.fillRect(-3,-5,6,10);
                    _cg.x=20+Math.random()*(W-40); _cg.y=-12;
                    scene.tweens.add({targets:_cg,y:H+20,x:_cg.x+(Math.random()*70-35),angle:Math.random()*540-270,alpha:0,delay:Math.random()*450,duration:1100+Math.random()*700,ease:"Quad.easeIn",onComplete:()=>_cg.destroy()});
                }
                // Prize type icon popup at wheel center
                const _popEmoji=prize.type==="gem"?"💎":"✨";
                const _popTxt=scene.add.text(CX,WY,_popEmoji,{fontSize:"44px"}).setOrigin(0.5).setDepth(D+23).setAlpha(0).setScale(0.4);
                scene.tweens.add({targets:_popTxt,alpha:1,scale:1.2,y:WY-20,duration:220,ease:"Back.easeOut",onComplete:()=>{
                    scene.tweens.add({targets:_popTxt,alpha:0,scale:0.6,y:WY-50,duration:400,delay:700,ease:"Quad.easeIn",onComplete:()=>_popTxt.destroy()});
                }});
                showBigReward(scene, CX, WY, prize.type, prize.amount, D+10);
            }
        });
    }
}


// ═══════════════════════════════════════════════════════════════
// §6  SHOP — 5 tabs, scrollable, fully functional
// ═══════════════════════════════════════════════════════════════

function showShop(scene, defaultTab, scrollTarget){
    let _cleanupSc=()=>{};
    const {A,close,contentTop,contentBot,CX:cx,depth:D,PW}
        =NT_OpenPopup(scene,"mm_panel",330,CURRENT_LANG==="tr"?"MAGAZA":"SHOP",312,20,()=>_cleanupSc(),"shop");
    scene.time.delayedCall(80, ()=>{ if(typeof NT_VL!=="undefined") NT_VL.play("welcome_shop", scene); });

    // ── TAB BAR ────────────────────────────────────────────────
    let _tab=defaultTab||"skins";
    // scrollTarget sadece ilk açılışta kullanılır
    let _pendingScroll = scrollTarget || null;
    const TH=30, TY=contentTop+18;
    const tabs=CURRENT_LANG==="tr"
        ?[{k:"skins",l:"KOSTUM"},{k:"chest",l:"SANDIK"},{k:"flash",l:"FIRSATLAR"},{k:"gems",l:"NF GEM"},{k:"power",l:"GUC"},{k:"boost",l:"TAKVIYE"}]
        :[{k:"skins",l:"SKINS"},{k:"chest",l:"CHEST"},{k:"flash",l:"OFFERS"},{k:"gems",l:"NF GEM"},{k:"power",l:"POWER"},{k:"boost",l:"BOOST"}];
    const TC=tabs.length, TWid=Math.floor((PW-16)/TC)-2;
    const TX0=cx-(TC*TWid+(TC-1)*4)/2;
    const tG={},tT={};

    tabs.forEach((td,i)=>{
        const tx=TX0+i*(TWid+4);
        tG[td.k]=A(scene.add.graphics().setDepth(D+3));
        tT[td.k]=A(scene.add.text(tx+TWid/2,TY,td.l,{fontFamily:_F,fontSize:"11px",color:"#fff",stroke:"#000",strokeThickness:2}).setOrigin(0.5).setDepth(D+5));
        A(scene.add.rectangle(tx+TWid/2,TY,TWid,TH,0xffffff,0.001).setDepth(D+6).setInteractive({useHandCursor:true}))
            .on("pointerdown",()=>{if(_tab===td.k)return;NT_SFX.play("menu_click");_tab=td.k;_rT();_sh();});
    });

    function _rT(){
        tabs.forEach((td,i)=>{
            const on=(_tab===td.k), tx=TX0+i*(TWid+4), g=tG[td.k];
            g.clear();
            g.fillStyle(on?0xcc7700:0x0c1c2e,1);
            g.fillRoundedRect(tx,TY-TH/2,TWid,TH,{tl:8,tr:8,bl:0,br:0});
            if(on){g.fillStyle(0xffffff,0.12);g.fillRoundedRect(tx+2,TY-TH/2+3,TWid-4,TH/2-4,4);}
            g.lineStyle(on?2:1,on?0xffe066:0x1e4060,on?0.95:0.50);
            g.strokeRoundedRect(tx,TY-TH/2,TWid,TH,{tl:8,tr:8,bl:0,br:0});
            tT[td.k].setColor(on?"#ffe066":"#4a7aaa").setFontSize(on?"11px":"10px");
        });
    }
    _rT();

    // ── SCROLL AREA SETUP ────────────────────────────────────
    const SY0=TY+TH/2+4;
    const VIEW_H=contentBot-SY0-4;
    const VPORT_X=cx-PW/2+10, VPORT_W=PW-20;

    const maskGfx=scene.add.graphics().setDepth(D+1);
    maskGfx.fillStyle(0xffffff,1);
    maskGfx.fillRect(VPORT_X,SY0,VPORT_W,VIEW_H);
    const geomMask=maskGfx.createGeometryMask();
    maskGfx.setVisible(false);

    let _scrollCont=null;
    let _scrollItems=[];
    let _scrollY=0, _scrollMax=0;
    let _dragStartY=0, _dragStartSY=0, _isDragging=false;
    // Tracks infinite-repeat tweens (e.g. LEGENDARY glow) so they're killed on tab switch
    let _activeTweens=[];

    function _destroyScroll(){
        // Kill all infinite tweens before destroying their targets (prevents per-frame update on dead objects)
        _activeTweens.forEach(t=>{try{t.stop();t.remove();}catch(_){}});
        _activeTweens=[];
        if(_scrollCont){
            try{scene.tweens.killTweensOf(_scrollCont);}catch(_){}
            try{_scrollCont.each(child=>{scene.tweens.killTweensOf(child);});}catch(_){}
            try{_scrollCont.destroy();}catch(_){}
        }
        _scrollCont=null;
        _scrollItems=[];
        _scrollY=0;
    }

    function _mkScrollCont(){
        _destroyScroll();
        _activeTweens=[];
        _scrollCont=scene.add.container(0,0).setDepth(D+4);
        _scrollCont.setMask(geomMask);
        A(_scrollCont);
        return _scrollCont;
    }

    function _scrollTo(y){
        _scrollY=Math.max(0,Math.min(_scrollMax,y));
        if(_scrollCont) _scrollCont.y=-_scrollY;
    }

    // Drag-to-scroll on the scroll zone hit area
    const scrollHit=A(scene.add.rectangle(cx,SY0+VIEW_H/2,VPORT_W,VIEW_H,0xffffff,0.001).setDepth(D+7).setInteractive({draggable:false}));
    scrollHit.on("pointerdown",(p)=>{_isDragging=false;_dragStartY=p.y;_dragStartSY=_scrollY;});
    scrollHit.on("pointermove",(p)=>{if(!p.isDown)return;if(Math.abs(p.y-_dragStartY)>6)_isDragging=true;if(_isDragging)_throttledScroll(_dragStartSY-(p.y-_dragStartY));});
    scrollHit.on("pointerup",(p)=>{
        if(!_isDragging){
            const worldY=p.y+_scrollY-SY0;
            for(const z of _scrollItems){
                if(p.x>=z.x1&&p.x<=z.x2&&worldY>=z.y1&&worldY<=z.y2){z.fn();break;}
            }
        }
        _isDragging=false;
    });

    // Mouse wheel scroll support
    const _shopWheelHandler=(pointer,gameObjects,dx,dy)=>{
        _scrollTo(_scrollY+dy*0.5);
    };
    scene.input.on("wheel",_shopWheelHandler);

    // Frame throttle: prevents redundant container repositioning within same render frame
    let _lastScrollFrame=-1;
    const _throttledScroll=(y)=>{
        const frame=scene.game&&scene.game.loop?scene.game.loop.frame:-1;
        if(frame!==_lastScrollFrame){ _lastScrollFrame=frame; _scrollTo(y); }
    };

    // ── TAB CONTENT BUILDERS ────────────────────────────────

    function _zone(x1,y1,x2,y2,fn){
        _scrollItems.push({x1:cx-PW/2+x1,x2:cx-PW/2+x2,y1,y2,fn});
    }

    function _sh(){
      try {
        // Cleanup carousel hit zone from a prior offers render (prevents input leaking into other tabs)
        if(scene._offersCarHit){ try{scene._offersCarHit.destroy();}catch(_){} scene._offersCarHit=null; }
        _scrollItems=[];
        _destroyScroll();
        const cont=_mkScrollCont();
        let totalH=0;
        let _goldPacksY=0, _gemPacksY=0; // scroll hedefi — case dışından erişilebilir

        function _add(o){cont.add(o);return o;}
        function G(){return scene.add.graphics();}
        function T(x,y,txt,style){return scene.add.text(x,y,txt,style);}

        function _btn(x,y,bw,bh,label,col,borderCol,fn){
            const bg=G();
            bg.fillStyle(0x000000,0.35);
            bg.fillRoundedRect(x-bw/2+2,y-bh/2+3,bw,bh,8);
            bg.fillStyle(col,1);
            bg.fillRoundedRect(x-bw/2,y-bh/2,bw,bh,8);
            bg.fillStyle(0xffffff,0.14);
            bg.fillRoundedRect(x-bw/2+4,y-bh/2+3,bw-8,bh*0.4,{tl:6,tr:6,bl:0,br:0});
            bg.lineStyle(2,borderCol,0.85);
            bg.strokeRoundedRect(x-bw/2,y-bh/2,bw,bh,8);
            const txt=T(x,y,label,{fontFamily:_F,fontSize:"13px",color:"#fff",stroke:"#000",strokeThickness:2}).setOrigin(0.5);
            _add(bg); _add(txt);
        }

        // Helper to add gold/gem icon in scroll container
        function _addCurrIcon(x,y,type,sz){
            if(scene.textures.exists(type==="gold"?"icon_gold":"icon_gem")){
                const ic=scene.add.image(x,y,type==="gold"?"icon_gold":"icon_gem").setDisplaySize(sz,sz);
                _add(ic);
            }
        }

        switch(_tab){
            // ───────────────── POWER ──────────────────────
            case "power":{
                let y=8;
                // Gold header with icon
                const goldHdr=G();
                goldHdr.fillStyle(0x0a1828,0.98);goldHdr.fillRoundedRect(cx-PW/2+10,SY0+y,PW-20,38,6);
                goldHdr.lineStyle(1.5,0xffcc00,0.5);goldHdr.strokeRoundedRect(cx-PW/2+10,SY0+y,PW-20,38,6);
                _add(goldHdr);
                _addCurrIcon(cx-PW/2+30,SY0+y+19,"gold",26);
                _add(T(cx-PW/2+50,SY0+y+19,PLAYER_GOLD.toLocaleString(),{fontFamily:_F,fontSize:"20px",color:"#ffcc00",stroke:"#000",strokeThickness:2}).setOrigin(0,0.5));
                _add(T(cx+PW/2-14,SY0+y+19,CURRENT_LANG==="tr"?"Mevcut Altın":"Current Gold",{fontFamily:_F,fontSize:"11px",color:"#667788",stroke:"#000",strokeThickness:1}).setOrigin(1,0.5));
                y+=46;
                // Süreli güç bilgi satırı
                const _infoG=G();_infoG.fillStyle(0x0c1e30,0.70);_infoG.fillRoundedRect(cx-PW/2+10,SY0+y,PW-20,22,5);_add(_infoG);
                _add(T(cx,SY0+y+11,CURRENT_LANG==="tr"?"⏱  Güçler süreli — süre dolunca yenile":"⏱  Powers expire — renew after duration ends",{fontFamily:_F,fontSize:"11px",color:"#5a8aaa",stroke:"#000",strokeThickness:1}).setOrigin(0.5));
                y+=30;
                GOLD_UPGRADES.forEach((u)=>{
                    const mx=u.level>=u.maxLevel;
                    const cost=Math.floor(u.baseCost*Math.pow(1.6,u.level));
                    const isAct=pwrIsActive(u.id);
                    const can=!mx&&PLAYER_GOLD>=cost;
                    const rowH=130, ry=SY0+y; // 130: desc origin(0,0) → status @ry+72, pill @ry+109 → needs 130px
                    const fill=u.level/u.maxLevel;
                    const bdrCol = mx?0x44cc44 : isAct?0x44ccaa : (u.level>0&&!isAct)?0xff4444 : can?0x44aacc : 0x1e3a50;
                    const accentCol = mx?0x44cc44 : isAct?0x33ddaa : (u.level>0&&!isAct)?0xff4444 : 0x4488cc;
                    // Drop shadow
                    const sh=G();sh.fillStyle(0x000000,0.50);sh.fillRoundedRect(cx-PW/2+13,ry+5,PW-20,rowH,10);_add(sh);
                    // Card gradient
                    const bg2=G();
                    if(mx){bg2.fillGradientStyle(0x001a06,0x001a06,0x000e04,0x000e04,1,1,1,1);}
                    else if(isAct){bg2.fillGradientStyle(0x001a10,0x001a10,0x000e08,0x000e08,1,1,1,1);}
                    else if(u.level>0){bg2.fillGradientStyle(0x1a0606,0x1a0606,0x0e0303,0x0e0303,1,1,1,1);}
                    else{bg2.fillGradientStyle(0x0c1020,0x0c1020,0x06080e,0x06080e,1,1,1,1);}
                    bg2.fillRoundedRect(cx-PW/2+10,ry,PW-20,rowH,10);
                    bg2.fillStyle(accentCol,0.07);bg2.fillRoundedRect(cx-PW/2+10,ry,PW-20,rowH,10);
                    bg2.fillStyle(0xffffff,0.06);bg2.fillRoundedRect(cx-PW/2+12,ry+2,PW-24,rowH*0.32,{tl:8,tr:8,bl:0,br:0});
                    bg2.lineStyle(isAct||mx?2:1.5,bdrCol,isAct||mx?0.90:0.55);bg2.strokeRoundedRect(cx-PW/2+10,ry,PW-20,rowH,10);
                    // Left accent stripe
                    bg2.fillStyle(accentCol,1);bg2.fillRoundedRect(cx-PW/2+10,ry,6,rowH,{tl:10,bl:10,tr:0,br:0});
                    if(isAct||mx){bg2.lineStyle(1,accentCol,0.25);bg2.strokeRoundedRect(cx-PW/2+14,ry+4,PW-28,rowH-8,7);}
                    _add(bg2);
                    // Icon badge circle (left)
                    const iconX=cx-PW/2+36, iconY=ry+rowH/2-4;
                    const ig=G();
                    ig.fillStyle(0x000000,0.45);ig.fillCircle(iconX+2,iconY+3,24);
                    ig.fillStyle(accentCol,0.20);ig.fillCircle(iconX,iconY,24);
                    ig.lineStyle(1.5,accentCol,0.75);ig.strokeCircle(iconX,iconY,24);
                    _add(ig);
                    _add(scene.add.text(iconX,iconY,u.icon||"⚡",{fontFamily:"Arial, sans-serif",fontSize:"22px"}).setOrigin(0.5).setDepth(D+4));
                    // Level pill
                    const lvStr="Lv "+u.level+"/"+u.maxLevel;
                    const lvPillW=44, lvPillH=16;
                    const lvPg=G();
                    lvPg.fillStyle(0x000000,0.55);lvPg.fillRoundedRect(iconX-lvPillW/2+1,ry+rowH-20,lvPillW,lvPillH,6);
                    lvPg.fillStyle(mx?0x113311:isAct?0x0a2215:0x0c1525,1);lvPg.fillRoundedRect(iconX-lvPillW/2,ry+rowH-21,lvPillW,lvPillH,6);
                    lvPg.lineStyle(1,accentCol,0.60);lvPg.strokeRoundedRect(iconX-lvPillW/2,ry+rowH-21,lvPillW,lvPillH,6);
                    _add(lvPg);
                    _add(T(iconX,ry+rowH-13,lvStr,{fontFamily:_F,fontSize:"8px",color:mx?"#44ff66":isAct?"#44ffaa":"#88aacc",stroke:"#000",strokeThickness:1}).setOrigin(0.5));
                    // Name + desc
                    _add(T(cx-PW/2+66,ry+14,(CURRENT_LANG==="tr"?u.nameTR||L(u.nameKey):L(u.nameKey)),{fontFamily:_F,fontSize:"14px",color:"#ffffff",stroke:"#000",strokeThickness:2}).setOrigin(0,0.5));
                    // origin(0,0): desc starts at ry+30 and grows downward only — no upward overlap into name
                    _add(T(cx-PW/2+66,ry+30,(CURRENT_LANG==="tr"?u.descTxtTR:u.descTxt)||"",{fontFamily:_F,fontSize:"9px",color:"#6699aa",stroke:"#000",strokeThickness:1,wordWrap:{width:PW-180}}).setOrigin(0,0));
                    // Status block starts at ry+72 — enough room for 3-line desc (3×11px=33px → ry+30+33=ry+63)
                    const stBg=G();
                    const stX=cx-PW/2+66, stW=PW-174, stY=ry+72;
                    if(u.level>0){
                        if(isAct){
                            const remMs=(()=>{try{const d=JSON.parse(localStorage.getItem("nt_power_exp")||"{}");const e=d[u.id];return e?Math.max(0,e.expiresAt-Date.now()):0;}catch(_){return 0;}})();
                            const remH=Math.floor(remMs/3600000);
                            const remD=Math.floor(remMs/86400000);
                            const timeStr=remD>0?remD+(CURRENT_LANG==="tr"?"g ":"d ")+(remH%24)+(CURRENT_LANG==="tr"?"s":"h"):remH+(CURRENT_LANG==="tr"?"s":"h");
                            const progFrac=Math.min(1,remMs/(u.durationDays*86400000));
                            stBg.fillStyle(0x0a2010,0.90);stBg.fillRoundedRect(stX,stY,stW,30,5);
                            stBg.lineStyle(1,0x44cc88,0.45);stBg.strokeRoundedRect(stX,stY,stW,30,5);
                            stBg.fillStyle(0x082010,1);stBg.fillRoundedRect(stX+4,stY+18,stW-8,8,3);
                            stBg.fillStyle(0x44ee88,0.90);stBg.fillRoundedRect(stX+4,stY+18,(stW-8)*progFrac,8,3);
                            _add(stBg);
                            _add(T(stX+6,stY+10,"✅ "+timeStr+" "+(CURRENT_LANG==="tr"?"kaldı":"left"),{fontFamily:_F,fontSize:"10px",color:"#44ffaa",stroke:"#000",strokeThickness:1}).setOrigin(0,0.5));
                        } else {
                            stBg.fillStyle(0x200808,0.90);stBg.fillRoundedRect(stX,stY,stW,30,5);
                            stBg.lineStyle(1,0xaa3333,0.50);stBg.strokeRoundedRect(stX,stY,stW,30,5);
                            _add(stBg);
                            _add(T(stX+6,stY+15,(CURRENT_LANG==="tr"?"⚠ Süre doldu — Yenile":"⚠ Expired — Renew"),{fontFamily:_F,fontSize:"9px",color:"#ff6655",stroke:"#000",strokeThickness:1}).setOrigin(0,0.5));
                        }
                    } else {
                        stBg.fillStyle(0x0c1828,0.70);stBg.fillRoundedRect(stX,stY,stW,30,5);_add(stBg);
                        _add(T(stX+6,stY+15,(CURRENT_LANG==="tr"?u.durationDays+"G KORUMA · İlk alım":u.durationDays+"D SHIELD · First buy"),{fontFamily:_F,fontSize:"9px",color:"#5a88aa",stroke:"#000",strokeThickness:1}).setOrigin(0,0.5));
                    }
                    // MAX badge
                    if(mx){
                        const mxBg=G();
                        mxBg.fillStyle(0x000000,0.30);mxBg.fillRoundedRect(cx+PW/2-80,ry+2,56,18,5);
                        mxBg.fillGradientStyle(0x004a00,0x004a00,0x002200,0x002200,1,1,1,1);mxBg.fillRoundedRect(cx+PW/2-81,ry+1,56,18,5);
                        mxBg.lineStyle(1,0x44ee44,0.70);mxBg.strokeRoundedRect(cx+PW/2-81,ry+1,56,18,5);_add(mxBg);
                        _add(T(cx+PW/2-53,ry+10,"MAX LV",{fontFamily:_F,fontSize:"9px",color:"#44ff66",stroke:"#000",strokeThickness:1}).setOrigin(0.5));
                    }
                    // Buy/Renew button
                    if(!mx){
                        const renewMode = u.level>0 && !isAct;
                        const bx=cx+PW/2-46, bw=76, bh=44;
                        const btnBgCol = renewMode?(can?0x2a1000:0x1a0800):(can?0x0e2414:0x141414);
                        const btnBdCol = renewMode?(can?0xee8833:0x442222):(can?0x33cc66:0x224422);
                        const btnBg=G();
                        btnBg.fillStyle(0x000000,0.35);btnBg.fillRoundedRect(bx-bw/2+2,ry+rowH/2-bh/2+3,bw,bh,9);
                        btnBg.fillStyle(btnBgCol,1);btnBg.fillRoundedRect(bx-bw/2,ry+rowH/2-bh/2,bw,bh,9);
                        btnBg.fillStyle(0xffffff,can?0.08:0.02);btnBg.fillRoundedRect(bx-bw/2+4,ry+rowH/2-bh/2+4,bw-8,bh*0.38,6);
                        btnBg.lineStyle(1.8,btnBdCol,can?0.88:0.35);btnBg.strokeRoundedRect(bx-bw/2,ry+rowH/2-bh/2,bw,bh,9);_add(btnBg);
                        const costStr=cost.toLocaleString();
                        const costW2=costStr.length*8;const startX=bx-(32+5+costW2)/2;
                        _addCurrIcon(startX+16,ry+rowH/2,"gold",32);
                        _add(T(startX+36,ry+rowH/2,costStr,{fontFamily:_F,fontSize:"13px",color:can?"#ffcc44":"#554400",stroke:"#000",strokeThickness:2}).setOrigin(0,0.5));
                        _zone(PW-20-bw,y,PW-10,y+rowH,()=>{
                            const c2=Math.floor(u.baseCost*Math.pow(1.6,u.level));
                            if(u.level>=u.maxLevel||PLAYER_GOLD<c2){scene.cameras.main.shake(30,0.006);return;}
                            PLAYER_GOLD-=c2;secureSet("nt_gold",PLAYER_GOLD);
                            u.level++;
                            const sv=JSON.parse(localStorage.getItem("nt_shop")||"{}");sv[u.id]=u.level;localStorage.setItem("nt_shop",JSON.stringify(sv));
                            pwrActivate(u.id, u.durationDays);
                            NT_SFX.play("upgrade_select");
                            scene.cameras.main.shake(40,0.008);
                            for(let pi=0;pi<10;pi++){const ang=(Math.PI*2/10)*pi;const p2=scene.add.graphics().setDepth(D+25);p2.fillStyle(renewMode?0xff8833:0x44ff66,0.9);p2.fillCircle(0,0,3);p2.x=bx;p2.y=ry+rowH/2;scene.tweens.add({targets:p2,x:bx+Math.cos(ang)*44,y:ry+rowH/2+Math.sin(ang)*28,alpha:0,duration:380,ease:"Quad.easeOut",onComplete:()=>p2.destroy()});}
                            const upTxt=scene.add.text(bx,ry+rowH/2-10,"✓",{fontFamily:_F,fontSize:"22px",color:renewMode?"#ffaa44":"#44ff66",stroke:"#000",strokeThickness:3}).setOrigin(0.5).setDepth(D+26).setAlpha(0);
                            scene.tweens.add({targets:upTxt,alpha:1,y:ry+rowH/2-34,duration:350,ease:"Back.easeOut"});
                            scene.time.delayedCall(900,()=>scene.tweens.add({targets:upTxt,alpha:0,duration:250,onComplete:()=>upTxt.destroy()}));
                            _sh();
                        });
                    }
                    y+=rowH+8;
                });
                totalH=y+10;
                break;
            }
            // ───────────────── CHEST ──────────────────────
            case "chest":{
                let y=6;
                // ── SECTION HEADER ──────────────────────────────────────────
                {
                    const dX=cx-PW/2+10, dW=PW-20, dH=32;
                    const dg=G();
                    dg.fillStyle(0x000000,0.40); dg.fillRoundedRect(dX+2,SY0+y+3,dW,dH,8);
                    dg.fillGradientStyle(0x100c00,0x100c00,0x060400,0x060400,1,1,1,1);
                    dg.fillRoundedRect(dX,SY0+y,dW,dH,8);
                    dg.fillStyle(0xffcc00,1); dg.fillRect(dX,SY0+y+6,3,dH-12);
                    dg.fillStyle(0xffffff,0.07); dg.fillRoundedRect(dX+3,SY0+y,dW-3,Math.round(dH*0.44),{tl:0,tr:8,bl:0,br:0});
                    dg.lineStyle(1.5,0xffcc00,0.50); dg.strokeRoundedRect(dX,SY0+y,dW,dH,8);
                    _add(dg);
                    _add(T(cx,SY0+y+dH/2,CURRENT_LANG==="tr"?"🎁  KOSTüM SANDIKLARI":"🎁  SKIN CHESTS",{fontFamily:_F,fontSize:"13px",color:"#ffdd88",stroke:"#000",strokeThickness:2}).setOrigin(0.5));
                    y+=dH+8;
                }
                CHESTS.forEach((ch,ci)=>{
                    const rowH=88, canB=PLAYER_GEMS>=ch.cost;
                    const cg=G();
                    // Premium card with drop shadow
                    cg.fillStyle(0x000000,0.55);cg.fillRoundedRect(cx-PW/2+13,SY0+y+5,PW-20,rowH,10);
                    cg.fillGradientStyle(0x0e1828,0x0e1828,0x060c18,0x060c18,1,1,1,1);
                    cg.fillRoundedRect(cx-PW/2+10,SY0+y,PW-20,rowH,10);
                    cg.fillStyle(ch.col,0.08);cg.fillRoundedRect(cx-PW/2+10,SY0+y,PW-20,rowH,10);
                    cg.fillStyle(0xffffff,0.05);cg.fillRoundedRect(cx-PW/2+12,SY0+y+3,PW-24,rowH*0.38,{tl:8,tr:8,bl:0,br:0});
                    cg.lineStyle(canB?2:1.5,ch.col,canB?0.80:0.35);cg.strokeRoundedRect(cx-PW/2+10,SY0+y,PW-20,rowH,10);
                    // Left accent
                    cg.fillStyle(ch.col,1);cg.fillRoundedRect(cx-PW/2+10,SY0+y,5,rowH,{tl:10,bl:10,tr:0,br:0});
                    if(ch.tag){
                        cg.fillStyle(0xffaa00,1);cg.fillRoundedRect(cx+PW/2-88,SY0+y,70,16,{tl:0,tr:9,bl:5,br:0});
                        cg.fillStyle(0xffffff,0.18);cg.fillRoundedRect(cx+PW/2-88,SY0+y,70,8,{tl:0,tr:9,bl:0,br:0});
                    }
                    _add(cg);
                    if(ch.tag) _add(T(cx+PW/2-53,SY0+y+8,ch.tag,{fontFamily:_F,fontSize:"9px",color:"#fff",stroke:"#000",strokeThickness:1}).setOrigin(0.5));

                    // Chest image — floating animation
                    const chestKey = ["common","rare","exotic","legendary","event"][ci] + "_chest";
                    const _chestImgKey = "chest_"+["common","rare","exotic","legendary","event"][ci];
                    const chestImgX = cx-PW/2+46;
                    const chestImgY = SY0+y+rowH/2;
                    if(scene.textures.exists(_chestImgKey)){
                        const chImg = scene.add.image(chestImgX, chestImgY, _chestImgKey)
                            .setDisplaySize(62,62).setDepth(D+4);
                        _add(chImg);
                        // Floating idle animation
                        scene.tweens.add({
                            targets:chImg, y:chestImgY-5,
                            duration:1400+ci*200, ease:"Sine.easeInOut",
                            yoyo:true, repeat:-1, delay:ci*180
                        });
                        // Subtle glow pulse (scale)
                        scene.tweens.add({
                            targets:chImg, scaleX:{from:1,to:1.04}, scaleY:{from:1,to:1.04},
                            duration:1800, ease:"Sine.easeInOut",
                            yoyo:true, repeat:-1, delay:ci*280
                        });
                    }

                    // Text info right of chest
                    const txX = cx-PW/2+80;
                    _add(T(txX,SY0+y+20,(CURRENT_LANG==="tr"&&ch.nameTR?(ch.nameTR+" SANDIK"):ch.name+" CHEST"),{fontFamily:_F,fontSize:"15px",color:"#ffffff",stroke:"#000",strokeThickness:2}).setOrigin(0,0.5));
                    const tierNames=CURRENT_LANG==="tr"?["SIRADAN","NADIR","EGZOTIK","EFSANE"]:["Common","Rare","Exotic","Legendary"];
                    let infoStr="";
                    ch.tierWeights.forEach((tw,ti)=>{if(tw>0)infoStr+=(infoStr?" · ":"")+tierNames[ti]+" "+tw+"%";});
                    _add(T(txX,SY0+y+38,infoStr,{fontFamily:_F,fontSize:"8px",color:"#6a9abb",stroke:"#000",strokeThickness:1,wordWrap:{width:PW-160}}).setOrigin(0,0.5));
                    _add(T(txX,SY0+y+56,"⚔️  "+( CURRENT_LANG==="tr"?"Silah & Kostüm Skinleri":"Weapon & Character Skins"),{fontFamily:_F,fontSize:"9px",color:"#88aacc",stroke:"#000",strokeThickness:1}).setOrigin(0,0.5));
                    _add(T(txX,SY0+y+70,ch.cost+" 💎 "+( CURRENT_LANG==="tr"?"gerekir":"needed"),{fontFamily:_F,fontSize:"9px",color:"#9966cc",stroke:"#000",strokeThickness:1}).setOrigin(0,0.5));

                    const bx=cx+PW/2-48,bw=68,bh=32;
                    _btn(bx,SY0+y+rowH/2,bw,bh,CURRENT_LANG==="tr"?"YAKINDA":"SOON",0x1a1830,0x443366,null);
                    y+=rowH+6;
                });
                totalH=y+10;
                break;
            }
            // ───────────────── BOOST ──────────────────────
            case "boost":{
                let y=6;
                const actB=BOOSTS.filter(b=>_isB(b.id));
                if(actB.length>0){
                    const abH=22+actB.length*20+6;
                    const abg=G();
                    abg.fillStyle(0x0a1e10,0.97);abg.fillRoundedRect(cx-PW/2+10,SY0+y,PW-20,abH,7);
                    abg.lineStyle(1,0x44aa44,0.4);abg.strokeRoundedRect(cx-PW/2+10,SY0+y,PW-20,abH,7);
                    _add(abg);
                    _add(T(cx,SY0+y+11,CURRENT_LANG==="tr"?"AKTIF TAKVIYELER":"ACTIVE BOOSTS",{fontFamily:_F,fontSize:"12px",color:"#44ff66",stroke:"#000",strokeThickness:1}).setOrigin(0.5));
                    actB.forEach((b,i)=>{
                        const bi=_s().bo[b.id];let info="";
                        if(b.dur>0&&bi){const r=b.dur-(Date.now()-bi.a);if(r>0)info=" ("+_fmt(r)+")";}
                        else if(bi&&(bi.u||0)>0)info=" ("+bi.u+(CURRENT_LANG==="tr"?"x kullanim)":" x uses)");
                        _add(T(cx,SY0+y+24+i*20,(CURRENT_LANG==="tr"&&b.nameTR?b.nameTR:b.name)+info,{fontFamily:_F,fontSize:"12px",color:"#88ffaa",stroke:"#000",strokeThickness:1}).setOrigin(0.5));
                    });
                    y+=abH+8;
                }
                BOOSTS.forEach((b)=>{
                    const isAct=_isB(b.id),canB=PLAYER_GEMS>=b.cost;
                    const rowH=88;
                    // Drop shadow
                    const sh=G();
                    sh.fillStyle(0x000000,0.50);sh.fillRoundedRect(cx-PW/2+13,SY0+y+5,PW-20,rowH,10);_add(sh);
                    // Card gradient
                    const bg2=G();
                    if(isAct){bg2.fillGradientStyle(0x001a0d,0x001a0d,0x000e08,0x000e08,1,1,1,1);}
                    else{bg2.fillGradientStyle(0x0c0c20,0x0c0c20,0x060612,0x060612,1,1,1,1);}
                    bg2.fillRoundedRect(cx-PW/2+10,SY0+y,PW-20,rowH,10);
                    bg2.fillStyle(b.col,isAct?0.12:0.06);bg2.fillRoundedRect(cx-PW/2+10,SY0+y,PW-20,rowH,10);
                    bg2.fillStyle(0xffffff,0.06);bg2.fillRoundedRect(cx-PW/2+12,SY0+y+2,PW-24,rowH*0.35,{tl:8,tr:8,bl:0,br:0});
                    bg2.lineStyle(isAct?2:1.5,b.col,isAct?0.90:0.50);bg2.strokeRoundedRect(cx-PW/2+10,SY0+y,PW-20,rowH,10);
                    bg2.fillStyle(b.col,1);bg2.fillRoundedRect(cx-PW/2+10,SY0+y,6,rowH,{tl:10,bl:10,tr:0,br:0});
                    if(isAct){bg2.lineStyle(1,b.col,0.28);bg2.strokeRoundedRect(cx-PW/2+14,SY0+y+4,PW-28,rowH-8,7);}
                    _add(bg2);
                    // Icon circle
                    const iconX=cx-PW/2+36, iconY=SY0+y+rowH/2-6;
                    const ig=G();
                    ig.fillStyle(0x000000,0.45);ig.fillCircle(iconX+2,iconY+3,22);
                    ig.fillStyle(b.col,0.22);ig.fillCircle(iconX,iconY,22);
                    ig.lineStyle(1.5,b.col,0.75);ig.strokeCircle(iconX,iconY,22);
                    _add(ig);
                    _add(scene.add.text(iconX,iconY,b.icon,{fontFamily:"Arial, sans-serif",fontSize:"20px"}).setOrigin(0.5).setDepth(D+4));
                    // Name
                    _add(T(cx-PW/2+64,SY0+y+18,(CURRENT_LANG==="tr"&&b.nameTR?b.nameTR:b.name),{fontFamily:_F,fontSize:"13px",color:"#ffffff",stroke:"#000",strokeThickness:2}).setOrigin(0,0.5));
                    // origin(0,0): desc grows downward only — no upward bleed into name
                    _add(T(cx-PW/2+64,SY0+y+33,(CURRENT_LANG==="tr"&&b.descTR?b.descTR:b.desc),{fontFamily:_F,fontSize:"9px",color:"#7799bb",stroke:"#000",strokeThickness:1,wordWrap:{width:PW-174}}).setOrigin(0,0));
                    // Active timer
                    if(isAct){
                        const bi=_s().bo[b.id];let timeStr="";
                        if(b.dur>0&&bi){const r=Math.max(0,b.dur-(Date.now()-bi.a));timeStr=_fmt(r)+(CURRENT_LANG==="tr"?" kaldı":" left");}
                        else if(bi&&(bi.u||0)>0){timeStr=(bi.u)+(CURRENT_LANG==="tr"?"x kullanım":" uses left");}
                        if(timeStr){
                            const tg=G();
                            tg.fillStyle(0x002a10,0.90);tg.fillRoundedRect(cx-PW/2+64,SY0+y+48,PW-166,18,5);
                            tg.lineStyle(1,b.col,0.50);tg.strokeRoundedRect(cx-PW/2+64,SY0+y+48,PW-166,18,5);_add(tg);
                            _add(T(cx-PW/2+72,SY0+y+57,"✅ "+timeStr,{fontFamily:_F,fontSize:"9px",color:"#55ffaa",stroke:"#000",strokeThickness:1}).setOrigin(0,0.5));
                        }
                    }
                    // Button
                    const bx=cx+PW/2-46,bw=76,bh=36;
                    if(isAct){
                        const ab=G();
                        ab.fillStyle(0x000000,0.30);ab.fillRoundedRect(bx-bw/2+2,SY0+y+rowH/2-bh/2+3,bw,bh,9);
                        ab.fillStyle(0x0a2210,1);ab.fillRoundedRect(bx-bw/2,SY0+y+rowH/2-bh/2,bw,bh,9);
                        ab.fillStyle(0xffffff,0.07);ab.fillRoundedRect(bx-bw/2+4,SY0+y+rowH/2-bh/2+4,bw-8,bh*0.40,6);
                        ab.lineStyle(1.5,0x44cc66,0.75);ab.strokeRoundedRect(bx-bw/2,SY0+y+rowH/2-bh/2,bw,bh,9);_add(ab);
                        _add(T(bx,SY0+y+rowH/2,CURRENT_LANG==="tr"?"✅ AKTİF":"✅ ACTIVE",{fontFamily:_F,fontSize:"11px",color:"#44ff88",stroke:"#000",strokeThickness:2}).setOrigin(0.5));
                    } else {
                        const btnBg=G();
                        btnBg.fillStyle(0x000000,0.35);btnBg.fillRoundedRect(bx-bw/2+2,SY0+y+rowH/2-bh/2+3,bw,bh,9);
                        btnBg.fillStyle(canB?0x2a0050:0x18001e,1);btnBg.fillRoundedRect(bx-bw/2,SY0+y+rowH/2-bh/2,bw,bh,9);
                        if(canB){btnBg.fillStyle(0xff55ff,0.08);btnBg.fillRoundedRect(bx-bw/2+4,SY0+y+rowH/2-bh/2+4,bw-8,bh*0.40,6);}
                        btnBg.lineStyle(1.8,canB?0xcc44ff:0x442255,canB?0.90:0.35);btnBg.strokeRoundedRect(bx-bw/2,SY0+y+rowH/2-bh/2,bw,bh,9);_add(btnBg);
                        const costStr=b.cost.toString();
                        const costW=costStr.length*8;const startX=bx-(18+4+costW)/2;
                        _addCurrIcon(startX+9,SY0+y+rowH/2,"gem",18);
                        _add(T(startX+22,SY0+y+rowH/2,costStr,{fontFamily:_F,fontSize:"13px",color:canB?"#ee99ff":"#553366",stroke:"#000",strokeThickness:2}).setOrigin(0,0.5));
                        _zone(PW-20-bw,y,PW-10,y+rowH,()=>{
                            if(PLAYER_GEMS<b.cost){scene.cameras.main.shake(30,0.006);return;}
                            spendGems(b.cost);_actB(b.id);NT_SFX.play("upgrade_select");
                            showBoosterReward(scene,cx,SY0+y,""+b.name,D+10);
                            scene.time.delayedCall(600,()=>_sh());
                        });
                    }
                    y+=rowH+8;
                });

                // ── LEVEL XP PAKETLERI — gem ile direkt level XP satin al ──
                const _xpPacks = CURRENT_LANG==="tr" ? [
                    { xp: 200,  cost: 5,  label: "+200 Level XP",  desc: "Hizli baslangic" },
                    { xp: 500,  cost: 10, label: "+500 Level XP",  desc: "Yavash ama saglam" },
                    { xp: 1200, cost: 20, label: "+1200 Level XP", desc: "Populer secim" },
                    { xp: 3000, cost: 45, label: "+3000 Level XP", desc: "Super boost" },
                ] : [
                    { xp: 200,  cost: 5,  label: "+200 Level XP",  desc: "Quick start" },
                    { xp: 500,  cost: 10, label: "+500 Level XP",  desc: "Slow but steady" },
                    { xp: 1200, cost: 20, label: "+1200 Level XP", desc: "Popular choice" },
                    { xp: 3000, cost: 45, label: "+3000 Level XP", desc: "Super boost" },
                ];
                const _lvXpNow = _plvXpNeeded(PLAYER_LEVEL);
                y+=4;
                {
                    const dX=cx-PW/2+10, dW=PW-20, dH=28;
                    const dg=G();
                    dg.fillStyle(0x000000,0.35); dg.fillRoundedRect(dX+2,SY0+y+3,dW,dH,7);
                    dg.fillGradientStyle(0x0e1000,0x0e1000,0x060800,0x060800,1,1,1,1);
                    dg.fillRoundedRect(dX,SY0+y,dW,dH,7);
                    dg.fillStyle(0xffcc00,1); dg.fillRect(dX,SY0+y+5,3,dH-10);
                    dg.fillStyle(0xffffff,0.06); dg.fillRoundedRect(dX+3,SY0+y,dW-3,Math.round(dH*0.44),{tl:0,tr:7,bl:0,br:0});
                    dg.lineStyle(1,0x997700,0.50); dg.strokeRoundedRect(dX,SY0+y,dW,dH,7);
                    _add(dg);
                    _add(T(cx,SY0+y+dH/2,CURRENT_LANG==="tr"?"⭐  LEVEL XP PAKETLERi":"⭐  LEVEL XP PACKS",{fontFamily:_F,fontSize:"12px",color:"#ffdd88",stroke:"#000",strokeThickness:2}).setOrigin(0.5));
                    y+=dH+6;
                }
                _xpPacks.forEach((pk)=>{
                    const rowH=56; const canB=PLAYER_GEMS>=pk.cost;
                    const xpFrac=Math.min(1,pk.xp/_lvXpNow);
                    const pg=G();
                    pg.fillStyle(0x0e1600,0.97);pg.fillRoundedRect(cx-PW/2+10,SY0+y,PW-20,rowH,8);
                    pg.lineStyle(1.5,canB?0xffcc00:0x443300,canB?0.65:0.30);pg.strokeRoundedRect(cx-PW/2+10,SY0+y,PW-20,rowH,8);
                    pg.fillStyle(0xffaa00,0.12);pg.fillRoundedRect(cx-PW/2+10,SY0+y,5,rowH,{tl:8,bl:8,tr:0,br:0});
                    // mini XP bar — ne kadar ilerleme saglar gosterir
                    pg.fillStyle(0x1a1000,1);pg.fillRoundedRect(cx-PW/2+22,SY0+y+rowH-14,PW-80,6,3);
                    pg.fillStyle(0xff9900,0.85);pg.fillRoundedRect(cx-PW/2+22,SY0+y+rowH-14,(PW-80)*xpFrac,6,3);
                    _add(pg);
                    _add(T(cx-PW/2+24,SY0+y+16,pk.label,{fontFamily:_F,fontSize:"14px",color:"#ffdd44",stroke:"#000",strokeThickness:2}).setOrigin(0,0.5));
                    _add(T(cx-PW/2+24,SY0+y+34,pk.desc,{fontFamily:_F,fontSize:"9px",color:"#997722",stroke:"#000",strokeThickness:1}).setOrigin(0,0.5));
                    const bx=cx+PW/2-52,bw=68,bh=28;
                    _btn(bx,SY0+y+rowH/2,bw,bh,pk.cost.toString(),canB?0x3a2800:0x1e1a0a,canB?0xffcc00:0x554400,null);
                    _addCurrIcon(bx-30,SY0+y+rowH/2,"gem",26);
                    _zone(PW-20-bw,y,PW-10,y+rowH,()=>{
                        if(PLAYER_GEMS<pk.cost){scene.cameras.main.shake(30,0.006);return;}
                        spendGems(pk.cost);
                        _plvAddXP(pk.xp);
                        NT_SFX.play("level_up");
                        scene.cameras.main.flash(200,255,200,0,false);
                        const popTxt=scene.add.text(cx,SY0+y,"+"+pk.xp+" XP!",{fontFamily:_F,fontSize:"18px",color:"#ffee44",stroke:"#000",strokeThickness:4}).setOrigin(0.5,0).setDepth(D+30).setAlpha(0);
                        scene.tweens.add({targets:popTxt,alpha:1,y:SY0+y-24,duration:300,ease:"Back.easeOut"});
                        scene.time.delayedCall(900,()=>scene.tweens.add({targets:popTxt,alpha:0,duration:250,onComplete:()=>popTxt.destroy()}));
                        scene.time.delayedCall(600,()=>_sh());
                    });
                    y+=rowH+6;
                });
                totalH=y+10;
                break;
            }
            case "skins":{
                // ════════════════════════════════════════════════════════════════
                // SKINS — AAA Premium Collectible Gallery
                // Clash Royale / Brawl Stars hero card quality
                // Rarity-driven full visual system: gradient bg + glow + badges
                // ════════════════════════════════════════════════════════════════
                let y = 6;
                const _F2 = "LilitaOne, Arial, sans-serif";
                const isTR = CURRENT_LANG === "tr";

                // ── Refresh timer ──────────────────────────────────────────────
                const _now24 = Date.now(), _dayMs = 86400000;
                const _nextR = _dayMs - (_now24 % _dayMs);
                const _rH = Math.floor(_nextR/3600000), _rM = Math.floor((_nextR%3600000)/60000);
                const _refStr = isTR ? `🔄 ${_rH}s ${_rM}dk` : `🔄 ${_rH}h ${_rM}m`;

                // ── RARITY SYSTEM — full visual definition ──────────────────────
                const _RAR = {
                    COMMON:    { en:"COMMON",    tr:"SIRADAN",  hex:"#99aabb",
                                 col:0x99aabb, glow:0x334455, topC:0x121e2a, botC:0x070c14, bdA:0.40 },
                    RARE:      { en:"RARE",      tr:"NADİR",    hex:"#44aaff",
                                 col:0x2288ff, glow:0x0d55cc, topC:0x081838, botC:0x030a1c, bdA:0.85 },
                    EXOTIC:    { en:"EXOTIC",    tr:"EGZOTİK",  hex:"#cc66ff",
                                 col:0xbb44ff, glow:0x7711cc, topC:0x14082c, botC:0x080416, bdA:0.95 },
                    LEGENDARY: { en:"LEGENDARY", tr:"EFSANE",   hex:"#ffcc00",
                                 col:0xffbb00, glow:0xcc7700, topC:0x221000, botC:0x0e0600, bdA:1.00 },
                };

                // ── CATEGORY DEFINITIONS ────────────────────────────────────────
                const _CATS = [
                    { cat:"char",   icon:"👤", en:"CHARACTER SKINS",  tr:"KARAKTER SKİNLERİ",  col:0xffdd44, hex:"#ffdd44" },
                    { cat:"bullet", icon:"💥", en:"BULLET EFFECTS",   tr:"MERMİ EFEKTLERİ",   col:0x66ddff, hex:"#66ddff" },
                    { cat:"weapon", icon:"⚔️", en:"WEAPON SKINS",     labelEN:"WEAPON SKINS",  col:0xddaa44, hex:"#ddaa44",
                      tr:"SİLAH SKİNLERİ" },
                ];

                // ── Card geometry (fixed, pixel-perfect) ───────────────────────
                const CW   = VPORT_W - 4;          // card width  ≈ 296
                const CX0  = cx - CW/2;             // card left edge
                const CH   = 90;                    // card height
                const ICO_R = 26;                   // icon circle radius
                const ICO_CX = CX0 + 4 + ICO_R + 8; // icon center X  = CX0+38
                const TXT_X  = CX0 + 4 + (ICO_R*2) + 20; // text start X  = CX0+76
                const BW   = 72, BH = 38;           // SOON button dims
                const BCX  = CX0 + CW - BW/2 - 4;  // button center X
                const TXT_W = BCX - BW/2 - 4 - TXT_X; // text zone width ≈ 136

                // ── Section header ──────────────────────────────────────────────
                const _secHdr = (cat) => {
                    const HDR = 46;
                    // Shadow
                    const shG = G();
                    shG.fillStyle(0x000000, 0.38);
                    shG.fillRoundedRect(CX0+2, SY0+y+4, CW, HDR, 10);
                    _add(shG);
                    // Body
                    const hG = G();
                    hG.fillGradientStyle(0x080e1c, 0x080e1c, 0x040810, 0x040810, 1,1,1,1);
                    hG.fillRoundedRect(CX0, SY0+y, CW, HDR, 10);
                    // Colored top strip (3px)
                    hG.fillStyle(cat.col, 1);
                    hG.fillRoundedRect(CX0, SY0+y, CW, 3, {tl:10,tr:10,bl:0,br:0});
                    // Sheen
                    hG.fillStyle(0xffffff, 0.055);
                    hG.fillRoundedRect(CX0+2, SY0+y+3, CW-4, HDR*0.40, {tl:8,tr:8,bl:0,br:0});
                    // Border
                    hG.lineStyle(1.5, cat.col, 0.65);
                    hG.strokeRoundedRect(CX0, SY0+y, CW, HDR, 10);
                    _add(hG);
                    // Icon + label
                    _add(T(CX0+14, SY0+y+HDR/2-5, cat.icon+'  '+(isTR?cat.tr:cat.en),
                        {fontFamily:_F2, fontSize:'13px', color:cat.hex, stroke:'#000', strokeThickness:3}
                    ).setOrigin(0, 0.5));
                    // Refresh timer right-aligned
                    _add(T(CX0+CW-10, SY0+y+HDR/2+8, _refStr,
                        {fontFamily:_F2, fontSize:'9px', color:'#3d6080', stroke:'#000', strokeThickness:1}
                    ).setOrigin(1, 0.5));
                    y += HDR + 7;
                };

                // ── Skin card builder ───────────────────────────────────────────
                const _skinCard = (sk) => {
                    const r    = _RAR[sk.rar] || _RAR.COMMON;
                    const name = isTR ? (sk.nameTR||sk.nameEN) : (sk.nameEN||sk.nameTR||'?');
                    const desc = isTR ? (sk.descTR||sk.descEN||'') : (sk.descEN||sk.descTR||'');
                    const rarLabel = isTR ? r.tr : r.en;
                    const CY = SY0 + y;              // card top in world coords
                    const icoCY = CY + CH/2;          // icon center Y

                    // ── Shadow ──────────────────────────────────────────────────
                    const shG = G();
                    shG.fillStyle(0x000000, 0.52);
                    shG.fillRoundedRect(CX0+3, CY+5, CW, CH, 10);
                    _add(shG);

                    // ── Card body — rarity gradient ─────────────────────────────
                    const bgG = G();
                    bgG.fillGradientStyle(r.topC, r.topC, r.botC, r.botC, 1,1,1,1);
                    bgG.fillRoundedRect(CX0, CY, CW, CH, 10);
                    // Rarity tint overlay
                    bgG.fillStyle(r.col, 0.055);
                    bgG.fillRoundedRect(CX0, CY, CW, CH, 10);
                    // Top sheen (depth highlight)
                    bgG.fillStyle(0xffffff, 0.055);
                    bgG.fillRoundedRect(CX0+2, CY+2, CW-4, CH*0.38, {tl:8,tr:8,bl:0,br:0});
                    // Left accent bar — solid rarity color
                    bgG.fillStyle(r.col, 1);
                    bgG.fillRoundedRect(CX0, CY, 4, CH, {tl:10,tr:0,bl:10,br:0});
                    // Bottom darkening strip
                    bgG.fillStyle(0x000000, 0.20);
                    bgG.fillRoundedRect(CX0+5, CY+CH-5, CW-5, 5, {tl:0,tr:0,bl:9,br:10});
                    // Border — rarity toned
                    bgG.lineStyle(1.5, r.col, r.bdA);
                    bgG.strokeRoundedRect(CX0, CY, CW, CH, 10);
                    bgG.lineStyle(1, 0xffffff, 0.08);
                    bgG.strokeRoundedRect(CX0+1, CY+1, CW-2, CH-2, 9);
                    _add(bgG);

                    // ── LEGENDARY: animated outer glow ─────────────────────────
                    if(sk.rar === "LEGENDARY") {
                        const lgG = G();
                        lgG.fillStyle(r.glow, 0.14);
                        lgG.fillRoundedRect(CX0-4, CY-4, CW+8, CH+8, 14);
                        lgG.lineStyle(2, r.col, 0.60);
                        lgG.strokeRoundedRect(CX0-2, CY-2, CW+4, CH+4, 12);
                        lgG.setAlpha(0.5);
                        _add(lgG);
                        const _lgTw=scene.tweens.add({targets:lgG, alpha:1.0, duration:1600, yoyo:true, repeat:-1, ease:'Sine.easeInOut'});
                        _activeTweens.push(_lgTw);
                    }

                    // ── EXOTIC: purple shimmer border ───────────────────────────
                    if(sk.rar === "EXOTIC") {
                        const exG = G();
                        exG.fillStyle(r.glow, 0.08);
                        exG.fillRoundedRect(CX0-3, CY-3, CW+6, CH+6, 13);
                        exG.lineStyle(1.5, r.col, 0.40);
                        exG.strokeRoundedRect(CX0-2, CY-2, CW+4, CH+4, 12);
                        _add(exG);
                    }

                    // ── RARE: subtle blue rim ───────────────────────────────────
                    if(sk.rar === "RARE") {
                        const reG = G();
                        reG.lineStyle(1.5, r.col, 0.30);
                        reG.strokeRoundedRect(CX0-2, CY-2, CW+4, CH+4, 12);
                        _add(reG);
                    }

                    // ── Icon circle — rarity-tinted with glow halo ─────────────
                    const icoG = G();
                    // Outer glow halo
                    icoG.fillStyle(r.glow, 0.25);
                    icoG.fillCircle(ICO_CX, icoCY, ICO_R+6);
                    icoG.fillStyle(r.glow, 0.12);
                    icoG.fillCircle(ICO_CX, icoCY, ICO_R+11);
                    // Icon base (dark)
                    icoG.fillStyle(r.topC, 1);
                    icoG.fillCircle(ICO_CX, icoCY, ICO_R);
                    // Skin tint fill
                    icoG.fillStyle(sk.tint || sk.col, 0.75);
                    icoG.fillCircle(ICO_CX, icoCY, ICO_R);
                    // Sheen highlight (top quarter)
                    icoG.fillStyle(0xffffff, 0.22);
                    icoG.fillCircle(ICO_CX, icoCY - ICO_R*0.30, ICO_R*0.55);
                    // Border
                    icoG.lineStyle(2, r.col, 0.95);
                    icoG.strokeCircle(ICO_CX, icoCY, ICO_R);
                    icoG.lineStyle(1, 0xffffff, 0.18);
                    icoG.strokeCircle(ICO_CX, icoCY, ICO_R-1);
                    _add(icoG);

                    // Category symbol inside icon
                    const sym = sk.cat==="bullet" ? "●" : sk.cat==="weapon" ? "✦" : "▲";
                    _add(T(ICO_CX, icoCY+1, sym,
                        {fontSize:'18px', color:'#ffffff', stroke:'#000', strokeThickness:3}
                    ).setOrigin(0.5));

                    // ── SKIN NAME — pixel-perfect, clamped ─────────────────────
                    const baseFS   = name.length > 18 ? 10 : name.length > 14 ? 11 : 13;
                    const nameTxt  = T(TXT_X, CY+14, name,
                        {fontFamily:_F2, fontSize:baseFS+'px', color:'#eef4ff', stroke:'#040810', strokeThickness:3}
                    ).setOrigin(0, 0.5);
                    if(nameTxt.width > TXT_W)
                        nameTxt.setFontSize(Math.max(9, Math.floor(baseFS*TXT_W/nameTxt.width))+'px');
                    _add(nameTxt);

                    // ── RARITY BADGE — colored pill ─────────────────────────────
                    const rarPW = Math.min(TXT_W-2, rarLabel.length*7+22);
                    const rarBY = CY + 30;
                    const rarBG = G();
                    rarBG.fillStyle(r.col, 0.18);
                    rarBG.fillRoundedRect(TXT_X, rarBY, rarPW, 17, 5);
                    rarBG.fillStyle(0xffffff, 0.06);
                    rarBG.fillRoundedRect(TXT_X+2, rarBY+2, rarPW-4, 7, {tl:4,tr:4,bl:0,br:0});
                    rarBG.lineStyle(1.5, r.col, 0.85);
                    rarBG.strokeRoundedRect(TXT_X, rarBY, rarPW, 17, 5);
                    _add(rarBG);
                    _add(T(TXT_X+rarPW/2, rarBY+8, rarLabel,
                        {fontFamily:_F2, fontSize:'9px', color:r.hex, stroke:'#000', strokeThickness:1}
                    ).setOrigin(0.5));

                    // ── DESCRIPTION — clamped, no overflow ─────────────────────
                    if(desc){
                        const descTxt = T(TXT_X, CY+56, desc,
                            {fontFamily:_F2, fontSize:'8px', color:'#5a7a9a',
                             stroke:'#000', strokeThickness:1, wordWrap:{width:TXT_W}}
                        ).setOrigin(0, 0.5);
                        // If two lines overflow card, shrink
                        if(descTxt.height > 20) descTxt.setFontSize('7px');
                        _add(descTxt);
                    }

                    // ── STAT BADGE — premium perk badge style ──────────────────
                    if(sk.dmgBonus > 0){
                        const statStr = '⚔ +' + Math.round(sk.dmgBonus*100) + '% DMG';
                        const stW = Math.min(TXT_W-2, statStr.length*6.5+16), stH = 17;
                        const stY = CY + CH - stH - 5;
                        const stG = G();
                        stG.fillStyle(0xffaa00, 0.22); stG.fillRoundedRect(TXT_X, stY, stW, stH, 4);
                        stG.fillStyle(0xffffff, 0.07); stG.fillRoundedRect(TXT_X+2, stY+2, stW-4, stH*0.45, {tl:3,tr:3,bl:0,br:0});
                        stG.lineStyle(1.5, 0xffcc44, 0.80); stG.strokeRoundedRect(TXT_X, stY, stW, stH, 4);
                        _add(stG);
                        _add(T(TXT_X+stW/2, stY+stH/2, statStr,
                            {fontFamily:_F2, fontSize:'8px', color:'#ffcc44', stroke:'#000', strokeThickness:1}
                        ).setOrigin(0.5));
                    }

                    // Special stat for bullet skins
                    if(sk.cat==="bullet" && sk.sound){
                        const sndStr = '♪ '+(isTR?'Özel Ses':'FX: ')+sk.sound.toUpperCase();
                        const sndW = Math.min(TXT_W-2, sndStr.length*6+16), sndH = 15;
                        const sndY = CY + CH - sndH - 5;
                        const sndG = G();
                        sndG.fillStyle(sk.col, 0.16); sndG.fillRoundedRect(TXT_X, sndY, sndW, sndH, 4);
                        sndG.lineStyle(1, sk.col, 0.55); sndG.strokeRoundedRect(TXT_X, sndY, sndW, sndH, 4);
                        _add(sndG);
                        _add(T(TXT_X+sndW/2, sndY+sndH/2, sndStr,
                            {fontFamily:_F2, fontSize:'8px', color:r.hex, stroke:'#000', strokeThickness:1}
                        ).setOrigin(0.5));
                    }

                    // ── SOON BUTTON ─────────────────────────────────────────────
                    const bY0 = CY + (CH-BH)/2;
                    const btnG = G();
                    // Button shadow
                    btnG.fillStyle(0x000000, 0.40);
                    btnG.fillRoundedRect(BCX-BW/2+2, bY0+3, BW, BH, 8);
                    // Button body
                    btnG.fillGradientStyle(0x0c1828, 0x0c1828, 0x060e18, 0x060e18, 1,1,1,1);
                    btnG.fillRoundedRect(BCX-BW/2, bY0, BW, BH, 8);
                    // Sheen
                    btnG.fillStyle(0xffffff, 0.05);
                    btnG.fillRoundedRect(BCX-BW/2+3, bY0+3, BW-6, BH*0.40, {tl:6,tr:6,bl:0,br:0});
                    // Border
                    btnG.lineStyle(1.5, 0x243855, 0.70);
                    btnG.strokeRoundedRect(BCX-BW/2, bY0, BW, BH, 8);
                    _add(btnG);
                    _add(T(BCX, CY+CH/2-6, isTR?'YAKINDA':'SOON',
                        {fontFamily:_F2, fontSize:'14px', color:'#3a5878', stroke:'#000', strokeThickness:2}
                    ).setOrigin(0.5));
                    _add(T(BCX, CY+CH/2+9, isTR?'GELİYOR':'COMING',
                        {fontFamily:_F2, fontSize:'8px', color:'#243855', stroke:'#000', strokeThickness:1}
                    ).setOrigin(0.5));

                    y += CH + 6;
                };

                // ── RENDER — sorted by rarity within each category ──────────────
                const _rarOrder = {COMMON:0, RARE:1, EXOTIC:2, LEGENDARY:3};
                _CATS.forEach(catDef => {
                    const catSkins = SKINS.filter(s => s.cat === catDef.cat);
                    if(catSkins.length === 0) return;
                    _secHdr(catDef);
                    [...catSkins]
                        .sort((a,b) => (_rarOrder[a.rar]||0) - (_rarOrder[b.rar]||0))
                        .forEach(sk => _skinCard(sk));
                    y += 14;
                });

                totalH = y + 16;
                break;
            }
            // ═══════════════════════════════════════════════════════════════════
            // OFFERS — PREMIUM CINEMATIC SWIPE CAROUSEL
            //   Brawl Stars / Clash Royale / Survivor.io monetization quality
            //   • PNG is the hero — fills 70% of each card
            //   • Horizontal swipe + snap with floating bob on active card
            //   • Tap → fullscreen cinematic inspect preview
            //   • All rewards are functional (gems/gold/booster actually granted)
            // ═══════════════════════════════════════════════════════════════════
            case "flash":{

                const NT_SHOP_OFFERS = [
                    { key:"offer_starter_pack",   title:"STARTER PACK",     price:"$2.99",  invoiceId:"sp",  gems:150,  gold:5000,  booster:"gold2x",   oneTime:true,  tag:"ONE TIME",   tagCol:0xff4422 },
                    { key:"offer_beginner_offer", title:"BEGINNER OFFER",   price:"$1.99",  invoiceId:"beg", gems:80,   gold:2000,                                    oneTime:false, tag:"STARTER",    tagCol:0x22bb55 },
                    { key:"offer_xp_pack",        title:"XP PACK",          price:"$4.99",  invoiceId:"xp",  gems:200,  gold:0,     booster:"xp2x",                  oneTime:false, tag:"POPULAR",    tagCol:0x2266cc },
                    { key:"offer_hero_bundle",    title:"HERO BUNDLE",      price:"$9.99",  invoiceId:"hb",  gems:400,  gold:15000,                                   oneTime:false, tag:"BUNDLE",     tagCol:0xaa22cc },
                    { key:"offer_nightmare_pack", title:"NIGHTMARE PACK",   price:"$14.99", invoiceId:"np",  gems:600,  gold:25000,                                   oneTime:false, tag:"HOT",        tagCol:0xff2200 },
                    { key:"offer_mega_value",     title:"MEGA VALUE",       price:"$19.99", invoiceId:"mv",  gems:1000, gold:40000,                                   oneTime:false, tag:"BEST VALUE", tagCol:0xffaa00 },
                    { key:"offer_premium_prog",   title:"PREMIUM PROGRESS", price:"$7.99",  invoiceId:"pp",  gems:300,  gold:10000, booster:"xp2x_24h",               oneTime:false, tag:"PRO",        tagCol:0x6644ff },
                ];

                // Returns array of {icon, label} chips — single source of truth for rewards
                const _summarize = (of) => {
                    const parts = [];
                    if(of.gems) parts.push({ icon:"icon_gem",  label:"+"+of.gems.toLocaleString() });
                    if(of.gold) parts.push({ icon:"icon_gold", label:"+"+of.gold.toLocaleString() });
                    if(of.booster){
                        const b = (typeof BOOSTS!=="undefined") ? BOOSTS.find(x=>x.id===of.booster) : null;
                        const lbl = b ? (CURRENT_LANG==="tr"?(b.nameTR||b.name):b.name) : "BOOST";
                        parts.push({ icon:null, label:"🚀 "+lbl });
                    }
                    return parts;
                };

                _scrollMax = 0; // carousel — no vertical scroll

                // ── Layout ──────────────────────────────────────────────────────────
                const DOTS_H  = 24;
                const PEEK    = 20;                        // side peek of adjacent card
                const cGap    = 12;
                const cardW   = PW - 2 * PEEK;            // big cinematic card
                const cardH   = Math.max(200, VIEW_H - DOTS_H - 10);
                const artH    = Math.round(cardH * 0.70); // PNG fills 70% — hero zone
                const stripH  = cardH - artH;
                const cardY   = SY0 + 4;
                const stride  = cardW + cGap;
                const N       = NT_SHOP_OFFERS.length;
                const R       = 18; // corner radius

                if(typeof scene._offersCurPage !== "number") scene._offersCurPage = 0;
                if(scene._offersCurPage >= N) scene._offersCurPage = 0;
                let _curPage = scene._offersCurPage;

                const _cardConts = [];

                NT_SHOP_OFFERS.forEach((offer, i) => {
                    const cc    = scene.add.container(cx + (i - _curPage) * stride, cardY);
                    cont.add(cc);
                    const bEdge = offer.tagCol || 0x4466cc;
                    const hw    = cardW / 2;

                    // Drop shadow
                    const shG = scene.add.graphics();
                    shG.fillStyle(0x000000, 0.72);
                    shG.fillRoundedRect(-hw + 5, 6, cardW, cardH, R + 2);
                    cc.add(shG);

                    // Card base
                    const bodyG = scene.add.graphics();
                    bodyG.fillGradientStyle(0x0c1624, 0x0c1624, 0x040810, 0x040810, 1,1,1,1);
                    bodyG.fillRoundedRect(-hw, 0, cardW, cardH, R);
                    cc.add(bodyG);

                    // PNG ART — hero zone, fills top 70%
                    if(scene.textures.exists(offer.key)){
                        const artImg = scene.add.image(0, artH/2, offer.key)
                            .setDisplaySize(cardW, artH).setOrigin(0.5, 0.5);
                        try{artImg.texture.setFilter(Phaser.Textures.FilterMode.LINEAR);}catch(_){}
                        cc.add(artImg);
                    } else {
                        const fbG = scene.add.graphics();
                        fbG.fillGradientStyle(0x1a1030, 0x2a0830, 0x080820, 0x080820, 1,1,1,1);
                        fbG.fillRoundedRect(-hw, 0, cardW, artH, {tl:R,tr:R,bl:0,br:0});
                        cc.add(fbG);
                    }

                    // Cinematic gradient over bottom of art — makes title readable
                    const ovG = scene.add.graphics();
                    const gradH = Math.round(artH * 0.58);
                    for(let s = 0; s < 9; s++){
                        const sy = artH - gradH + s * (gradH / 9);
                        ovG.fillStyle(0x000000, (s / 8) * 0.90);
                        ovG.fillRect(-hw, sy, cardW, gradH / 9 + 1);
                    }
                    cc.add(ovG);

                    // Title overlaid at bottom of art zone — large, dominant
                    const titleY = artH - 18;
                    cc.add(scene.add.text(0, titleY, offer.title,
                        {fontFamily:_F, fontSize:"18px", color:"#ffffff", stroke:"#000",
                         strokeThickness:5, align:"center"}).setOrigin(0.5, 1));

                    // TAG pill — top-left, premium colored
                    const tagTxt = offer.tag || "OFFER";
                    const tagW   = Math.max(66, tagTxt.length * 7.5 + 20);
                    const tagH   = 22;
                    const tpx    = 10, tpy = 10;
                    const tagG   = scene.add.graphics();
                    tagG.fillStyle(0x000000, 0.50);
                    tagG.fillRoundedRect(-hw + tpx + 2, tpy + 2, tagW, tagH, 11);
                    tagG.fillStyle(bEdge, 1);
                    tagG.fillRoundedRect(-hw + tpx, tpy, tagW, tagH, 11);
                    tagG.fillStyle(0xffffff, 0.22);
                    tagG.fillRoundedRect(-hw + tpx + 2, tpy + 2, tagW - 4, tagH / 2 - 2, {tl:9,tr:9,bl:0,br:0});
                    cc.add(tagG);
                    cc.add(scene.add.text(-hw + tpx + tagW/2, tpy + tagH/2, tagTxt,
                        {fontFamily:_F, fontSize:"10px", color:"#ffffff", stroke:"#000", strokeThickness:2}).setOrigin(0.5));

                    // ONE TIME badge — top-right burst
                    if(offer.oneTime){
                        const bG = scene.add.graphics();
                        bG.fillStyle(0x000000, 0.45); bG.fillCircle(hw - 24, 26, 22);
                        bG.fillStyle(0xff2200, 1);    bG.fillCircle(hw - 24, 24, 21);
                        bG.fillStyle(0xffffff, 0.18); bG.fillCircle(hw - 24, 16, 12);
                        bG.lineStyle(1.5, 0xff9966, 0.9); bG.strokeCircle(hw - 24, 24, 21);
                        cc.add(bG);
                        cc.add(scene.add.text(hw - 24, 20, "1x",
                            {fontFamily:_F, fontSize:"11px", color:"#fff", stroke:"#500", strokeThickness:2}).setOrigin(0.5));
                        cc.add(scene.add.text(hw - 24, 32, "ONLY",
                            {fontFamily:_F, fontSize:"7px", color:"#ffddbb", stroke:"#400", strokeThickness:1}).setOrigin(0.5));
                    }

                    // Bottom strip — BUY button only, clean
                    const sY = artH;
                    const sG = scene.add.graphics();
                    sG.fillGradientStyle(0x0e1830, 0x0e1830, 0x04080e, 0x04080e, 1,1,1,1);
                    sG.fillRoundedRect(-hw, sY, cardW, stripH, {tl:0,tr:0,bl:R,br:R});
                    sG.fillStyle(bEdge, 0.75);
                    sG.fillRect(-hw + 10, sY, cardW - 20, 1.5);
                    cc.add(sG);

                    // BUY button — full-width premium pill
                    const bW = cardW - 22;
                    const bH = Math.min(stripH - 14, 50);
                    const bY = sY + stripH / 2;
                    const btnG = scene.add.graphics();
                    btnG.fillStyle(0x000000, 0.60);
                    btnG.fillRoundedRect(-bW/2 + 3, bY - bH/2 + 5, bW, bH, 14);
                    btnG.fillGradientStyle(0x22dd55, 0x44ee77, 0x0d8830, 0x0d9935, 1,1,1,1);
                    btnG.fillRoundedRect(-bW/2, bY - bH/2, bW, bH, 14);
                    btnG.fillStyle(0xffffff, 0.24);
                    btnG.fillRoundedRect(-bW/2 + 4, bY - bH/2 + 4, bW - 8, bH * 0.38, {tl:10,tr:10,bl:0,br:0});
                    btnG.lineStyle(2.5, 0x55ff88, 0.95);
                    btnG.strokeRoundedRect(-bW/2, bY - bH/2, bW, bH, 14);
                    cc.add(btnG);
                    cc.add(scene.add.text(0, bY - 9, CURRENT_LANG==="tr" ? "SATIN AL" : "BUY NOW",
                        {fontFamily:_F, fontSize:"15px", color:"#ffffff", stroke:"#000", strokeThickness:3}).setOrigin(0.5));
                    cc.add(scene.add.text(0, bY + 10, offer.price,
                        {fontFamily:_F, fontSize:"13px", color:"#bbffcc", stroke:"#0a2200", strokeThickness:2}).setOrigin(0.5));

                    // Outer rim glow
                    const rimG = scene.add.graphics();
                    rimG.lineStyle(2, bEdge, 0.80);
                    rimG.strokeRoundedRect(-hw, 0, cardW, cardH, R);
                    rimG.lineStyle(1, 0xffffff, 0.11);
                    rimG.strokeRoundedRect(-hw + 1, 1, cardW - 2, cardH - 2, R - 1);
                    cc.add(rimG);

                    _cardConts.push({ container: cc, offer });
                });

                // ── Page indicator dots — pill style ────────────────────────────
                const dotsCY = SY0 + VIEW_H - DOTS_H / 2 - 2;
                const dotsG  = scene.add.graphics();
                cont.add(dotsG);

                const _drawDots = () => {
                    dotsG.clear();
                    const activePW = 20, inactivePW = 6, dotH = 6, dotGap = 6;
                    let totalDotsW = 0;
                    for(let i = 0; i < N; i++) totalDotsW += (i === _curPage ? activePW : inactivePW) + (i < N-1 ? dotGap : 0);
                    let dx = cx - totalDotsW / 2;
                    for(let i = 0; i < N; i++){
                        const pw = i === _curPage ? activePW : inactivePW;
                        if(i === _curPage){
                            const col = NT_SHOP_OFFERS[i].tagCol || 0xffcc44;
                            dotsG.fillStyle(col, 0.28);
                            dotsG.fillRoundedRect(dx - 3, dotsCY - dotH/2 - 3, pw + 6, dotH + 6, dotH/2 + 3);
                            dotsG.fillStyle(col, 1);
                            dotsG.fillRoundedRect(dx, dotsCY - dotH/2, pw, dotH, dotH/2);
                        } else {
                            dotsG.fillStyle(0x3a5a7a, 0.60);
                            dotsG.fillRoundedRect(dx, dotsCY - dotH/2, pw, dotH, dotH/2);
                        }
                        dx += pw + dotGap;
                    }
                };
                _drawDots();

                // ── Card layout with parallax scale/alpha ────────────────────────
                const _layout = (panOffset) => {
                    _cardConts.forEach((cd, i) => {
                        cd.container.x = cx + (i - _curPage) * stride + panOffset;
                        const dist = Math.abs(i - _curPage - panOffset / stride);
                        cd.container.setScale(Math.max(0.88, 1 - dist * 0.08));
                        cd.container.setAlpha(Math.max(0.48, 1 - dist * 0.36));
                    });
                };
                _layout(0);

                // Floating bob on active card
                const _startFloat = () => {
                    if(!_cardConts[_curPage]) return;
                    const tgt = _cardConts[_curPage].container;
                    scene.tweens.add({
                        targets: tgt,
                        y: { from: cardY - 3, to: cardY + 3 },
                        duration: 1700, yoyo: true, repeat: -1, ease: "Sine.easeInOut"
                    });
                };
                _startFloat();

                // ── Swipe hit zone ───────────────────────────────────────────────
                const carHit = scene.add.rectangle(cx, cardY + cardH/2, PW, cardH, 0xffffff, 0.001)
                    .setDepth(D + 9).setInteractive({useHandCursor:true});
                A(carHit);
                scene._offersCarHit = carHit;

                let _carDownX = 0, _carDownY = 0, _carDownTime = 0, _carDragging = false, _carPan = 0;
                const SWIPE_THRESHOLD = 10;
                const PAGE_FLIP_RATIO = 0.22;
                const FLICK_VELOCITY  = 0.55;

                const _snapToPage = (target, withFlick) => {
                    target = Math.max(0, Math.min(N - 1, target));
                    _curPage = target;
                    scene._offersCurPage = _curPage;
                    _carPan = 0;
                    _cardConts.forEach(cd => scene.tweens.killTweensOf(cd.container));
                    const startX  = _cardConts.map(cd => cd.container.x);
                    const targetX = _cardConts.map((_, i) => cx + (i - _curPage) * stride);
                    const tw = { t: 0 };
                    scene.tweens.add({
                        targets: tw, t: 1, duration: withFlick ? 200 : 270, ease: "Cubic.easeOut",
                        onUpdate: () => {
                            _cardConts.forEach((cd, i) => {
                                cd.container.x = startX[i] + (targetX[i] - startX[i]) * tw.t;
                                const dist = Math.abs(i - _curPage);
                                cd.container.setScale(Math.max(0.88, 1 - dist * 0.08));
                                cd.container.setAlpha(Math.max(0.48, 1 - dist * 0.36));
                            });
                            _drawDots();
                        },
                        onComplete: _startFloat
                    });
                };

                carHit.on('pointerdown', p => {
                    _carDownX = p.x; _carDownY = p.y; _carDownTime = Date.now(); _carDragging = false; _carPan = 0;
                });
                carHit.on('pointermove', p => {
                    if(!p.isDown) return;
                    const dx = p.x - _carDownX, dy = p.y - _carDownY;
                    if(!_carDragging && Math.abs(dx) > SWIPE_THRESHOLD && Math.abs(dx) > Math.abs(dy)) _carDragging = true;
                    if(_carDragging){
                        _carPan = dx;
                        if((_curPage === 0 && _carPan > 0) || (_curPage === N-1 && _carPan < 0)) _carPan *= 0.30;
                        _layout(_carPan);
                    }
                });
                carHit.on('pointerup', p => {
                    const dt   = Math.max(1, Date.now() - _carDownTime);
                    const dx   = p.x - _carDownX;
                    const dist = Math.hypot(dx, p.y - _carDownY);
                    if(_carDragging){
                        const vel = dx / dt;
                        let target = _curPage;
                        if(Math.abs(dx) > cardW * PAGE_FLIP_RATIO || Math.abs(vel) > FLICK_VELOCITY)
                            target = _curPage + (dx < 0 ? 1 : -1);
                        _snapToPage(target, Math.abs(vel) > FLICK_VELOCITY);
                        try{NT_SFX.playUI && NT_SFX.playUI('tab_switch');}catch(_){}
                    } else if(dist < 10 && dt < 380){
                        if(Math.abs(p.x - cx) < cardW/2) _openOfferPreview(_cardConts[_curPage].offer);
                        else if(p.x < cx) _snapToPage(_curPage - 1, false);
                        else _snapToPage(_curPage + 1, false);
                    }
                    _carDragging = false; _carPan = 0;
                });
                carHit.on('pointerout', () => {
                    if(_carDragging){ _snapToPage(_curPage, false); _carDragging = false; _carPan = 0; }
                });

                // ── Arrow nav buttons ────────────────────────────────────────────
                const _mkArrow = (side) => {
                    const ax  = cx + side * (PW / 2 - 11);
                    const ay  = cardY + cardH / 2;
                    const lbl = side < 0 ? "‹" : "›";
                    const aT  = scene.add.text(ax, ay, lbl,
                        {fontFamily:"Arial", fontSize:"24px", color:"#ffffff", stroke:"#000", strokeThickness:2})
                        .setOrigin(0.5).setDepth(D + 8).setAlpha(0.50);
                    cont.add(aT);
                    const aHit = scene.add.rectangle(ax, ay, 30, 50, 0xffffff, 0.001)
                        .setDepth(D + 10).setInteractive({useHandCursor:true});
                    cont.add(aHit);
                    aHit.on('pointerdown', () => {
                        aT.setAlpha(1);
                        _snapToPage(_curPage + (side > 0 ? 1 : -1), false);
                        try{NT_SFX.play && NT_SFX.play('menu_click');}catch(_){}
                    });
                    aHit.on('pointerup',  () => aT.setAlpha(0.50));
                    aHit.on('pointerout', () => aT.setAlpha(0.50));
                };
                _mkArrow(-1); _mkArrow(1);

                // ════════════════════════════════════════════════════════════════
                // FULLSCREEN OFFER PREVIEW — cinematic inspect mode
                //   Big PNG, dim backdrop, spring pop-in, real functional purchase
                // ════════════════════════════════════════════════════════════════
                function _openOfferPreview(offer){
                    try{NT_SFX.play("menu_click");}catch(_){}
                    const D2  = D + 200;
                    const GW  = 360, GH = 640;
                    const _objs = [];
                    const _Ap  = o => { _objs.push(o); return o; };

                    const _close = () => {
                        _objs.forEach(o => {
                            if(!o) return;
                            try {
                                if(o.setAlpha){
                                    scene.tweens.add({targets:o, alpha:0, duration:130, ease:"Quad.easeIn",
                                        onComplete:()=>{try{o.destroy();}catch(_){}}});
                                } else { o.destroy(); }
                            } catch(_) {}
                        });
                    };

                    // Full-screen scrim
                    const dim = _Ap(scene.add.rectangle(GW/2, GH/2, GW, GH, 0x000000, 0).setDepth(D2).setInteractive());
                    dim.on('pointerdown', _close);
                    scene.tweens.add({targets:dim, fillAlpha:0.88, duration:220, ease:"Quad.easeOut"});

                    // Panel geometry
                    const panW = 330, panH = 548;
                    const panX = GW/2, panY = GH/2;

                    // Shadow
                    const shadowG = _Ap(scene.add.graphics().setDepth(D2 + 1).setAlpha(0));
                    shadowG.fillStyle(0x000000, 0.72);
                    shadowG.fillRoundedRect(panX - panW/2 + 8, panY - panH/2 + 12, panW, panH, 26);

                    // Panel body
                    const panelG = _Ap(scene.add.graphics().setDepth(D2 + 2).setAlpha(0));
                    panelG.fillGradientStyle(0x101828, 0x101828, 0x040810, 0x040810, 1,1,1,1);
                    panelG.fillRoundedRect(panX - panW/2, panY - panH/2, panW, panH, 24);
                    // Colored accent bar at top
                    panelG.fillStyle(offer.tagCol || 0x4488ff, 1);
                    panelG.fillRoundedRect(panX - panW/2, panY - panH/2, panW, 5, {tl:24,tr:24,bl:0,br:0});
                    // Outer border
                    panelG.lineStyle(2.5, offer.tagCol || 0x4488ff, 0.95);
                    panelG.strokeRoundedRect(panX - panW/2, panY - panH/2, panW, panH, 24);
                    panelG.lineStyle(1, 0xffffff, 0.13);
                    panelG.strokeRoundedRect(panX - panW/2 + 2, panY - panH/2 + 2, panW - 4, panH - 4, 22);

                    // PNG — large, top section, preserves 2:1 aspect
                    const imgTop  = panY - panH/2 + 14;
                    const imgMaxW = panW - 18;
                    const imgMaxH = Math.round(panH * 0.47);
                    let imgW = imgMaxW;
                    let imgH = Math.round(imgW / 2);
                    if(imgH > imgMaxH){ imgH = imgMaxH; imgW = imgH * 2; }
                    const imgCY = imgTop + imgH / 2;

                    if(scene.textures.exists(offer.key)){
                        // Glow halo behind PNG
                        const glowG = _Ap(scene.add.graphics().setDepth(D2 + 2).setAlpha(0));
                        glowG.fillStyle(offer.tagCol || 0x4488ff, 0.16);
                        glowG.fillRoundedRect(panX - imgW/2 - 8, imgCY - imgH/2 - 8, imgW + 16, imgH + 16, 16);

                        const img = _Ap(scene.add.image(panX, imgCY, offer.key)
                            .setDisplaySize(imgW, imgH).setDepth(D2 + 3).setAlpha(0));
                        try{img.texture.setFilter(Phaser.Textures.FilterMode.LINEAR);}catch(_){}

                        const imgBorderG = _Ap(scene.add.graphics().setDepth(D2 + 3).setAlpha(0));
                        imgBorderG.lineStyle(2, offer.tagCol || 0x4488ff, 0.70);
                        imgBorderG.strokeRoundedRect(panX - imgW/2 - 1, imgCY - imgH/2 - 1, imgW + 2, imgH + 2, 8);
                    }

                    // Separator
                    const sepY = imgTop + imgMaxH + 16;
                    const sepG = _Ap(scene.add.graphics().setDepth(D2 + 2).setAlpha(0));
                    sepG.fillStyle(offer.tagCol || 0x4488ff, 0.38);
                    sepG.fillRect(panX - panW/2 + 22, sepY, panW - 44, 1);

                    // Title
                    const titleY = sepY + 24;
                    _Ap(scene.add.text(panX, titleY, offer.title,
                        {fontFamily:_F, fontSize:"23px", color:"#ffffff", stroke:"#000", strokeThickness:5, align:"center"})
                        .setOrigin(0.5).setDepth(D2 + 4).setAlpha(0));

                    // Reward chips with real PNG icons
                    const chips  = _summarize(offer);
                    const chipsY = titleY + 36;
                    const chipH  = 36;
                    const chipW  = 90;
                    const chipGap = 8;
                    const totalCW = chips.length * chipW + (chips.length - 1) * chipGap;
                    let chipX0 = panX - totalCW / 2;

                    const chipBgG = _Ap(scene.add.graphics().setDepth(D2 + 3).setAlpha(0));
                    chips.forEach((chip, ci) => {
                        const cx0 = chipX0 + ci * (chipW + chipGap);
                        chipBgG.fillStyle(0x000000, 0.48);
                        chipBgG.fillRoundedRect(cx0, chipsY - chipH/2, chipW, chipH, 10);
                        chipBgG.lineStyle(1.5, offer.tagCol || 0x4488ff, 0.45);
                        chipBgG.strokeRoundedRect(cx0, chipsY - chipH/2, chipW, chipH, 10);

                        if(chip.icon && scene.textures.exists(chip.icon)){
                            _Ap(scene.add.image(cx0 + 16, chipsY, chip.icon)
                                .setDisplaySize(22, 22).setDepth(D2 + 5).setAlpha(0));
                            _Ap(scene.add.text(cx0 + 30, chipsY, chip.label,
                                {fontFamily:_F, fontSize:"12px", color:"#ffffff", stroke:"#000", strokeThickness:2})
                                .setOrigin(0, 0.5).setDepth(D2 + 5).setAlpha(0));
                        } else {
                            _Ap(scene.add.text(cx0 + chipW/2, chipsY, chip.label,
                                {fontFamily:_F, fontSize:"12px", color:"#ffffff", stroke:"#000", strokeThickness:2})
                                .setOrigin(0.5, 0.5).setDepth(D2 + 5).setAlpha(0));
                        }
                    });

                    // BUY button — massive premium pill
                    const buyW = panW - 30;
                    const buyH = 64;
                    const buyY = panY + panH/2 - 50;
                    const buyG = _Ap(scene.add.graphics().setDepth(D2 + 3).setAlpha(0));
                    buyG.fillStyle(0x000000, 0.62);
                    buyG.fillRoundedRect(panX - buyW/2 + 4, buyY - buyH/2 + 6, buyW, buyH, 20);
                    buyG.fillGradientStyle(0x22ee66, 0x44ff88, 0x0b8830, 0x0b9935, 1,1,1,1);
                    buyG.fillRoundedRect(panX - buyW/2, buyY - buyH/2, buyW, buyH, 20);
                    buyG.fillStyle(0xffffff, 0.26);
                    buyG.fillRoundedRect(panX - buyW/2 + 6, buyY - buyH/2 + 6, buyW - 12, buyH * 0.38, {tl:16,tr:16,bl:0,br:0});
                    buyG.lineStyle(3, 0x66ffaa, 0.95);
                    buyG.strokeRoundedRect(panX - buyW/2, buyY - buyH/2, buyW, buyH, 20);

                    _Ap(scene.add.text(panX, buyY - 12, CURRENT_LANG==="tr" ? "ŞİMDİ SATIN AL" : "BUY NOW",
                        {fontFamily:_F, fontSize:"21px", color:"#ffffff", stroke:"#000", strokeThickness:5})
                        .setOrigin(0.5).setDepth(D2 + 5).setAlpha(0));
                    _Ap(scene.add.text(panX, buyY + 14, offer.price,
                        {fontFamily:_F, fontSize:"17px", color:"#ccffdd", stroke:"#0a2800", strokeThickness:3})
                        .setOrigin(0.5).setDepth(D2 + 5).setAlpha(0));

                    const buyHit = _Ap(scene.add.rectangle(panX, buyY, buyW, buyH, 0xffffff, 0.001)
                        .setDepth(D2 + 6).setInteractive({useHandCursor:true}));

                    // Close button — top-right
                    const cX = panX + panW/2 - 26, cY = panY - panH/2 + 26;
                    const clG = _Ap(scene.add.graphics().setDepth(D2 + 4).setAlpha(0));
                    clG.fillStyle(0x000000, 0.78); clG.fillCircle(cX, cY, 17);
                    clG.fillStyle(0x1a0808, 0.90); clG.fillCircle(cX, cY, 15);
                    clG.lineStyle(2, 0xff6655, 0.90); clG.strokeCircle(cX, cY, 15);
                    _Ap(scene.add.text(cX, cY, "✕",
                        {fontFamily:_F, fontSize:"16px", color:"#ff8866", stroke:"#000", strokeThickness:2})
                        .setOrigin(0.5).setDepth(D2 + 5));
                    const clHit = _Ap(scene.add.rectangle(cX, cY, 44, 44, 0xffffff, 0.001)
                        .setDepth(D2 + 7).setInteractive({useHandCursor:true}));
                    clHit.on('pointerdown', _close);

                    // Functional reward grant
                    const _grant = () => {
                        if(offer.gems)   addGems(offer.gems);
                        if(offer.gold) { PLAYER_GOLD += offer.gold; secureSet("nt_gold", PLAYER_GOLD); }
                        if(offer.booster) _actB(offer.booster);
                        try{NT_SFX.play("chest_open","legendary");}catch(_){}
                        scene.cameras.main.flash(400, 255, 200, 80, false);
                        if(offer.gems)      showBigReward(scene, panX, panY, "gem",  offer.gems,  D2 + 50);
                        else if(offer.gold) showBigReward(scene, panX, panY, "gold", offer.gold,  D2 + 50);
                    };

                    buyHit.on('pointerdown', () => {
                        try{NT_SFX.play("menu_click");}catch(_){}
                        scene.tweens.add({targets:buyG, scaleX:0.96, scaleY:0.96, duration:80, yoyo:true, ease:"Quad.easeOut"});
                    });
                    buyHit.on('pointerup', () => {
                        if(window.Telegram && window.Telegram.WebApp && window.Telegram.WebApp.openInvoice){
                            try {
                                window.Telegram.WebApp.openInvoice(offer.invoiceId, st => {
                                    if(st === "paid"){
                                        _grant();
                                        scene.time.delayedCall(900, () => { _close(); scene.time.delayedCall(150, ()=>_sh()); });
                                    }
                                });
                            } catch(_) {
                                _grant();
                                scene.time.delayedCall(700, () => { _close(); scene.time.delayedCall(150, ()=>_sh()); });
                            }
                        } else {
                            _grant();
                            scene.time.delayedCall(700, () => { _close(); scene.time.delayedCall(150, ()=>_sh()); });
                        }
                    });

                    // Animate in — fade + spring pop
                    _objs.forEach(o => {
                        if(o && o.setAlpha && o !== dim)
                            scene.tweens.add({targets:o, alpha:1, duration:280, ease:"Cubic.easeOut"});
                    });
                    [panelG, shadowG].forEach(g => {
                        if(g){ g.setScale(0.88); scene.tweens.add({targets:g, scaleX:1, scaleY:1, duration:300, ease:"Back.easeOut"}); }
                    });
                }

                totalH = 0;
                break;
            }


            // ───────────────── GEMS ──────────────────────
            case "gems":{
                const RC = 12;   // card corner radius
                let y = 6;

                // ── GEM BALANCE HEADER ──────────────────────────────────
                {
                    const hW=PW-20, hH=44, hX=cx-PW/2+10;
                    const hg=G();
                    hg.fillStyle(0x000000,0.40); hg.fillRoundedRect(hX+2,SY0+y+3,hW,hH,RC);
                    hg.fillGradientStyle(0x1a0038,0x1a0038,0x08001c,0x08001c,1,1,1,1);
                    hg.fillRoundedRect(hX,SY0+y,hW,hH,RC);
                    hg.fillStyle(0xffffff,0.07); hg.fillRoundedRect(hX+4,SY0+y+3,hW-8,Math.round(hH*0.42),{tl:RC-2,tr:RC-2,bl:0,br:0});
                    hg.lineStyle(2,0xcc44ff,0.65); hg.strokeRoundedRect(hX,SY0+y,hW,hH,RC);
                    _add(hg);
                    const _gs=PLAYER_GEMS.toLocaleString();
                    const _gw=_gs.length*11+42; const _gx=cx-_gw/2;
                    _addCurrIcon(_gx+16,SY0+y+hH/2,"gem",30);
                    _add(T(_gx+35,SY0+y+hH/2,_gs,{fontFamily:_F,fontSize:"20px",color:"#dd88ff",stroke:"#000",strokeThickness:2}).setOrigin(0,0.5));
                    y+=hH+8;
                }

                // ── STARTER PACK (one-time) ─────────────────────────────
                const s=_s();
                if(!s.sp){
                    const spH=66, spX=cx-PW/2+10, spW=PW-20;
                    const sg=G();
                    sg.fillStyle(0x000000,0.40); sg.fillRoundedRect(spX+2,SY0+y+3,spW,spH,RC);
                    sg.fillStyle(0x1c0830,1); sg.fillRoundedRect(spX,SY0+y,spW,spH,RC);
                    sg.fillStyle(0xffffff,0.07); sg.fillRoundedRect(spX+4,SY0+y+3,spW-8,Math.round(spH*0.40),{tl:RC-2,tr:RC-2,bl:0,br:0});
                    sg.lineStyle(2.5,0xff4488,0.90); sg.strokeRoundedRect(spX,SY0+y,spW,spH,RC);
                    sg.lineStyle(1,0xffffff,0.12); sg.strokeRoundedRect(spX+2,SY0+y+2,spW-4,spH-4,RC-2);
                    sg.fillStyle(0xff4488,0.05); sg.fillRoundedRect(spX,SY0+y,spW,spH,RC);
                    _add(sg);
                    _add(T(spX+14,SY0+y+18,(CURRENT_LANG==="tr"?"BASLANGIC — -":"NOT STARTER — -")+STARTER.disc+"% OFF",{fontFamily:_F,fontSize:"13px",color:"#ff88aa",stroke:"#000",strokeThickness:2}).setOrigin(0,0.5));
                    _add(T(spX+14,SY0+y+40,STARTER.gems+" GEMS  +  "+STARTER.gold+" GOLD  +  2× GOLD",{fontFamily:_F,fontSize:"11px",color:"#ffccdd",stroke:"#000",strokeThickness:1}).setOrigin(0,0.5));
                    _btn(cx+PW/2-54,SY0+y+spH/2,78,34,"⭐ "+STARTER.stars,0x88002a,0xff4488,null);
                    _zone(10,y,PW-10,y+spH,()=>{
                        const _buy=()=>{
                            showBigReward(scene,cx,SY0+y+spH/2,"gem",STARTER.gems,D+10);
                            PLAYER_GOLD+=STARTER.gold;secureSet("nt_gold",PLAYER_GOLD);_actB("gold2x");
                            const st=_s();st.sp=true;_sv(st);
                            scene.time.delayedCall(700,()=>_sh());
                        };
                        if(window.Telegram?.WebApp?.openInvoice){window.Telegram.WebApp.openInvoice("starter_pack",(st)=>{if(st==="paid")_buy();});}else _buy();
                    });
                    y+=spH+10;
                }

                _gemPacksY = y;

                // ── GEM SECTION DIVIDER ─────────────────────────────────
                {
                    const dX=cx-PW/2+10, dW=PW-20, dH=36;
                    const dg=G();
                    // Glow aura
                    dg.lineStyle(4,0xaa33ff,0.18); dg.strokeRoundedRect(dX-1,SY0+y+3,dW+2,dH-6,9);
                    // Background
                    dg.fillStyle(0x08001a,1); dg.fillRoundedRect(dX,SY0+y+4,dW,dH-8,8);
                    dg.fillStyle(0x1a0038,1); dg.fillRoundedRect(dX,SY0+y+4,dW,Math.round((dH-8)*0.5),{tl:8,tr:8,bl:0,br:0});
                    // Left accent bar
                    dg.fillStyle(0xaa33ff,1); dg.fillRect(dX,SY0+y+4,4,dH-8);
                    // Top sheen
                    dg.fillStyle(0xffffff,0.10); dg.fillRoundedRect(dX+4,SY0+y+4,dW-4,Math.round((dH-8)*0.38),{tl:0,tr:8,bl:0,br:0});
                    // Border
                    dg.lineStyle(1.5,0xaa33ff,0.72); dg.strokeRoundedRect(dX,SY0+y+4,dW,dH-8,8);
                    _add(dg);
                    _add(T(cx+8,SY0+y+dH/2,CURRENT_LANG==="tr"?"ELMAS PAKETLERİ":"GEM PACKS",{fontFamily:_F,fontSize:"14px",color:"#dd88ff",stroke:"#000",strokeThickness:2}).setOrigin(0.5));
                    y+=dH+6;
                }

                // ── GEM PACK CARDS ──────────────────────────────────────
                GEM_PACKS.forEach((pk,i)=>{
                    const tot=pk.gems+pk.bonus;
                    const rowH=118;
                    const cardX=cx-PW/2+10, cardW=PW-20;
                    const isHot=pk.tag==="best", isPop=pk.tag==="popular";
                    const glowCol=isHot?0xffaa00:isPop?0x5588ff:0x7722bb;
                    const bordCol=isHot?0xffaa00:isPop?0x5588ff:0x6633cc;

                    const pg=G();
                    // Outer glow aura
                    pg.fillStyle(glowCol,0.20); pg.fillRoundedRect(cardX-5,SY0+y-5,cardW+10,rowH+10,RC+4);
                    pg.fillStyle(glowCol,0.10); pg.fillRoundedRect(cardX-2,SY0+y-2,cardW+4,rowH+4,RC+2);
                    // Drop shadow
                    pg.fillStyle(0x000000,0.55); pg.fillRoundedRect(cardX+3,SY0+y+5,cardW,rowH,RC);
                    // Card body gradient
                    pg.fillGradientStyle(0x1e0840,0x1e0840,0x08021a,0x08021a,1,1,1,1);
                    pg.fillRoundedRect(cardX,SY0+y,cardW,rowH,RC);
                    // Top shimmer gloss
                    pg.fillStyle(0xffffff,0.08); pg.fillRoundedRect(cardX+4,SY0+y+3,cardW-8,Math.round(rowH*0.38),{tl:RC-2,tr:RC-2,bl:0,br:0});
                    // Side accent stripe (gem purple)
                    pg.fillStyle(0xaa33ff,1); pg.fillRect(cardX,SY0+y+RC,4,rowH-RC*2);
                    pg.fillStyle(glowCol,0.15); pg.fillRect(cardX,SY0+y+RC,4,rowH-RC*2);
                    // 2-layer border
                    pg.lineStyle(isHot||isPop?2.5:1.5,bordCol,isHot||isPop?0.90:0.55);
                    pg.strokeRoundedRect(cardX,SY0+y,cardW,rowH,RC);
                    pg.lineStyle(1,0xffffff,0.12); pg.strokeRoundedRect(cardX+2,SY0+y+2,cardW-4,rowH-4,RC-2);
                    _add(pg);

                    // Tag badge top-right
                    if(pk.tag){
                        const tagLabel=isHot?(CURRENT_LANG==="tr"?"BEST":"BEST VALUE"):(CURRENT_LANG==="tr"?"POPULER":"POPULAR");
                        const tagCol=isHot?0xcc7700:0x1a44cc;
                        const tW=80,tH=20;
                        const tg=G();
                        tg.fillStyle(0x000000,0.40); tg.fillRoundedRect(cardX+cardW-tW-1,SY0+y+1,tW,tH,{tl:0,tr:RC,bl:6,br:0});
                        tg.fillStyle(tagCol,1); tg.fillRoundedRect(cardX+cardW-tW,SY0+y,tW,tH,{tl:0,tr:RC,bl:6,br:0});
                        tg.fillStyle(0xffffff,0.22); tg.fillRoundedRect(cardX+cardW-tW,SY0+y,tW,tH*0.50,{tl:0,tr:RC-1,bl:0,br:0});
                        _add(tg);
                        _add(T(cardX+cardW-tW/2,SY0+y+tH/2,(isHot?"★ ":"⭐ ")+tagLabel,{fontFamily:_F,fontSize:"9px",color:"#fff",stroke:"#000",strokeThickness:1}).setOrigin(0.5));
                    }

                    // ASSET — left side, square, fills most of card height
                    const IMG_SZ=Math.min(rowH-10, 106);
                    const IMG_X=cardX+8+IMG_SZ/2, IMG_Y=SY0+y+rowH/2;
                    if(pk.packImg && scene.textures.exists(pk.packImg)){
                        const pkImg=scene.add.image(IMG_X,IMG_Y,pk.packImg).setDisplaySize(IMG_SZ,IMG_SZ);
                        try{
                            const gl=scene.renderer&&scene.renderer.gl;
                            const _ts=scene.textures.get(pk.packImg);
                            const _src=_ts&&_ts.source&&_ts.source[0];
                            if(gl&&_src&&_src.glTexture){
                                const aniso=gl.getExtension("EXT_texture_filter_anisotropic")||gl.getExtension("MOZ_EXT_texture_filter_anisotropic")||gl.getExtension("WEBKIT_EXT_texture_filter_anisotropic");
                                gl.bindTexture(gl.TEXTURE_2D,_src.glTexture);
                                gl.texParameteri(gl.TEXTURE_2D,gl.TEXTURE_WRAP_S,gl.CLAMP_TO_EDGE);
                                gl.texParameteri(gl.TEXTURE_2D,gl.TEXTURE_WRAP_T,gl.CLAMP_TO_EDGE);
                                gl.generateMipmap(gl.TEXTURE_2D);
                                gl.texParameteri(gl.TEXTURE_2D,gl.TEXTURE_MIN_FILTER,gl.LINEAR_MIPMAP_LINEAR);
                                gl.texParameteri(gl.TEXTURE_2D,gl.TEXTURE_MAG_FILTER,gl.LINEAR);
                                if(aniso){const mA=gl.getParameter(aniso.MAX_TEXTURE_MAX_ANISOTROPY_EXT);gl.texParameterf(gl.TEXTURE_2D,aniso.TEXTURE_MAX_ANISOTROPY_EXT,Math.min(8,mA));}
                                gl.bindTexture(gl.TEXTURE_2D,null);
                            }
                        }catch(_){}
                        _add(pkImg);
                    }else{
                        _addCurrIcon(IMG_X,IMG_Y,"gem",IMG_SZ);
                    }

                    // ── TEXT + BUTTON ZONE ─────────────────────────────────
                    // Layout: [IMG] [TITLE / AMOUNT+CHIP / BONUS] [BUY_BTN]
                    const TX=cardX+8+IMG_SZ+10;        // text zone start X
                    const BTN_W=70, BTN_H=rowH-16;     // buy button — tall, fills card height
                    const BTN_CX=cardX+cardW-6-BTN_W/2; // buy button center X
                    const BTN_CY=SY0+y+rowH/2;
                    const TXT_MAX_W=BTN_CX-BTN_W/2-8-TX; // max text width before button

                    // Row positions — evenly spaced inside card
                    const R1=SY0+y+18;  // title
                    const R2=SY0+y+50;  // amount hero text
                    const R3=SY0+y+82;  // bonus / chip row
                    const R4=SY0+y+98;  // unit chip row (if bonus pushed it)

                    // Pack title label
                    _add(T(TX,R1,pk.title||"",{fontFamily:_F,fontSize:"11px",color:"#aa77dd",stroke:"#000",strokeThickness:1}).setOrigin(0,0.5));

                    // AMOUNT — hero white text, auto-shrink if needed
                    const totStr=tot.toLocaleString();
                    const amtT=T(TX,R2,totStr,{fontFamily:_F,fontSize:"22px",color:"#ffffff",stroke:"#0a001a",strokeThickness:3}).setOrigin(0,0.5);
                    if(amtT.width>TXT_MAX_W-46) amtT.setFontSize(18);
                    if(amtT.width>TXT_MAX_W-46) amtT.setFontSize(15);
                    _add(amtT);

                    // "GEMS" chip — beside amount, same row
                    const chipG=G();
                    const cpX=TX+amtT.width+3, cpW=42, cpH=16;
                    chipG.fillStyle(0x4a1188,1); chipG.fillRoundedRect(cpX,R2-cpH/2,cpW,cpH,5);
                    chipG.fillStyle(0xffffff,0.15); chipG.fillRoundedRect(cpX,R2-cpH/2,cpW,cpH*0.5,{tl:5,tr:5,bl:0,br:0});
                    chipG.lineStyle(1.5,0xcc55ff,0.90); chipG.strokeRoundedRect(cpX,R2-cpH/2,cpW,cpH,5);
                    _add(chipG);
                    _add(T(cpX+cpW/2,R2,CURRENT_LANG==="tr"?"ELMAS":"GEMS",{fontFamily:_F,fontSize:"9px",color:"#ee99ff",stroke:"#000",strokeThickness:1}).setOrigin(0.5));

                    // BONUS badge
                    if(pk.bonus>0){
                        const bonG=G();
                        const bnW=Math.min(TXT_MAX_W,96),bnH=20;
                        bonG.fillStyle(0x0a2a00,1); bonG.fillRoundedRect(TX,R3-bnH/2,bnW,bnH,6);
                        bonG.fillStyle(0x1a5500,1); bonG.fillRoundedRect(TX,R3-bnH/2,bnW,bnH*0.5,{tl:6,tr:6,bl:0,br:0});
                        bonG.lineStyle(1.5,0x55cc22,0.85); bonG.strokeRoundedRect(TX,R3-bnH/2,bnW,bnH,6);
                        _add(bonG);
                        _add(T(TX+bnW/2,R3,"+ "+pk.bonus.toLocaleString()+" BONUS",{fontFamily:_F,fontSize:"10px",color:"#88ff44",stroke:"#000",strokeThickness:1}).setOrigin(0.5));
                    }

                    // BUY BUTTON — tall, right-aligned, premium gem style
                    const btnG=G();
                    // Shadow
                    btnG.fillStyle(0x000000,0.55); btnG.fillRoundedRect(BTN_CX-BTN_W/2+3,BTN_CY-BTN_H/2+5,BTN_W,BTN_H,11);
                    // Body gradient
                    btnG.fillGradientStyle(0x9944dd,0x9944dd,0x3a0a7a,0x3a0a7a,1,1,1,1);
                    btnG.fillRoundedRect(BTN_CX-BTN_W/2,BTN_CY-BTN_H/2,BTN_W,BTN_H,11);
                    // Top sheen
                    btnG.fillStyle(0xffffff,0.20); btnG.fillRoundedRect(BTN_CX-BTN_W/2+4,BTN_CY-BTN_H/2+4,BTN_W-8,BTN_H*0.35,{tl:9,tr:9,bl:0,br:0});
                    // Bottom glow strip
                    btnG.fillStyle(0xcc55ff,0.30); btnG.fillRoundedRect(BTN_CX-BTN_W/2,BTN_CY+BTN_H/2-5,BTN_W,5,{tl:0,tr:0,bl:9,br:9});
                    // Border
                    btnG.lineStyle(2.5,0xdd66ff,1.0); btnG.strokeRoundedRect(BTN_CX-BTN_W/2,BTN_CY-BTN_H/2,BTN_W,BTN_H,11);
                    btnG.lineStyle(1,0xffffff,0.22); btnG.strokeRoundedRect(BTN_CX-BTN_W/2+2,BTN_CY-BTN_H/2+2,BTN_W-4,BTN_H-4,9);
                    _add(btnG);
                    // Icon + price vertically stacked inside button
                    _addCurrIcon(BTN_CX,BTN_CY-10,"gem",22);
                    _add(T(BTN_CX,BTN_CY+12,pk.price,{fontFamily:_F,fontSize:"13px",color:"#ffffff",stroke:"#000",strokeThickness:2}).setOrigin(0.5));

                    _zone(0,y,PW-10,y+rowH,()=>{
                        if(window.Telegram?.WebApp?.openInvoice){
                            window.Telegram.WebApp.openInvoice("gem_"+i,(st)=>{
                                if(st==="paid"){showBigReward(scene,cx,SY0+y+rowH/2,"gem",tot,D+10);scene.time.delayedCall(700,()=>_sh());}
                            });
                        }
                    });
                    y+=rowH+10;
                });

                // ── GOLD PACKS SECTION ──────────────────────────────────
                y+=6;
                _goldPacksY = y;

                // Gold balance header
                {
                    const hW=PW-20, hH=44, hX=cx-PW/2+10;
                    const hg=G();
                    hg.fillStyle(0x000000,0.40); hg.fillRoundedRect(hX+2,SY0+y+3,hW,hH,RC);
                    hg.fillGradientStyle(0x2a1400,0x2a1400,0x0e0600,0x0e0600,1,1,1,1);
                    hg.fillRoundedRect(hX,SY0+y,hW,hH,RC);
                    hg.fillStyle(0xffffff,0.07); hg.fillRoundedRect(hX+4,SY0+y+3,hW-8,Math.round(hH*0.42),{tl:RC-2,tr:RC-2,bl:0,br:0});
                    hg.lineStyle(2,0xffcc00,0.65); hg.strokeRoundedRect(hX,SY0+y,hW,hH,RC);
                    _add(hg);
                    const _gs2=PLAYER_GOLD.toLocaleString();
                    const _gw2=_gs2.length*11+42; const _gx2=cx-_gw2/2;
                    _addCurrIcon(_gx2+16,SY0+y+hH/2,"gold",30);
                    _add(T(_gx2+35,SY0+y+hH/2,_gs2,{fontFamily:_F,fontSize:"20px",color:"#ffdd44",stroke:"#000",strokeThickness:2}).setOrigin(0,0.5));
                    y+=hH+8;
                }

                // Gold section divider
                {
                    const dX=cx-PW/2+10, dW=PW-20, dH=36;
                    const dg=G();
                    // Glow aura
                    dg.lineStyle(4,0xffaa00,0.18); dg.strokeRoundedRect(dX-1,SY0+y+3,dW+2,dH-6,9);
                    // Background
                    dg.fillStyle(0x0e0600,1); dg.fillRoundedRect(dX,SY0+y+4,dW,dH-8,8);
                    dg.fillStyle(0x1e0e00,1); dg.fillRoundedRect(dX,SY0+y+4,dW,Math.round((dH-8)*0.5),{tl:8,tr:8,bl:0,br:0});
                    // Left accent bar
                    dg.fillStyle(0xffcc00,1); dg.fillRect(dX,SY0+y+4,4,dH-8);
                    // Top sheen
                    dg.fillStyle(0xffffff,0.10); dg.fillRoundedRect(dX+4,SY0+y+4,dW-4,Math.round((dH-8)*0.38),{tl:0,tr:8,bl:0,br:0});
                    // Border
                    dg.lineStyle(1.5,0xffaa00,0.72); dg.strokeRoundedRect(dX,SY0+y+4,dW,dH-8,8);
                    _add(dg);
                    _add(T(cx+8,SY0+y+dH/2,CURRENT_LANG==="tr"?"ALTIN PAKETLERİ":"GOLD PACKS",{fontFamily:_F,fontSize:"14px",color:"#ffdd44",stroke:"#000",strokeThickness:2}).setOrigin(0.5));
                    y+=dH+6;
                }

                const GOLD_PACKS=[
                    {gold:6000,   price:"$1.99",  bonus:0,     tag:null,      title:"SMALL",  packImg:"pack_gold_s"},
                    {gold:15000,  price:"$4.99",  bonus:3000,  tag:"popular", title:"MEDIUM", packImg:"pack_gold_m"},
                    {gold:40000,  price:"$9.99",  bonus:12000, tag:null,      title:"LARGE",  packImg:"pack_gold_l"},
                    {gold:100000, price:"$19.99", bonus:35000, tag:"best",    title:"MEGA",   packImg:"pack_gold_xl"},
                ];
                GOLD_PACKS.forEach((gp,i)=>{
                    const tot=gp.gold+(gp.bonus||0);
                    const rowH=118;
                    const cardX=cx-PW/2+10, cardW=PW-20;
                    const isHot=gp.tag==="best", isPop=gp.tag==="popular";
                    const glowCol=isHot?0xff8800:isPop?0xffcc00:0xcc8800;
                    const bordCol=isHot?0xff8800:isPop?0xffcc00:0xaa7700;

                    const gg=G();
                    gg.fillStyle(glowCol,0.20); gg.fillRoundedRect(cardX-5,SY0+y-5,cardW+10,rowH+10,RC+4);
                    gg.fillStyle(glowCol,0.10); gg.fillRoundedRect(cardX-2,SY0+y-2,cardW+4,rowH+4,RC+2);
                    gg.fillStyle(0x000000,0.55); gg.fillRoundedRect(cardX+3,SY0+y+5,cardW,rowH,RC);
                    gg.fillGradientStyle(0x2a1400,0x2a1400,0x0e0600,0x0e0600,1,1,1,1);
                    gg.fillRoundedRect(cardX,SY0+y,cardW,rowH,RC);
                    gg.fillStyle(0xffffff,0.07); gg.fillRoundedRect(cardX+4,SY0+y+3,cardW-8,Math.round(rowH*0.38),{tl:RC-2,tr:RC-2,bl:0,br:0});
                    // Left accent stripe (gold orange)
                    gg.fillStyle(0xffaa00,1); gg.fillRect(cardX,SY0+y+RC,4,rowH-RC*2);
                    gg.fillStyle(glowCol,0.15); gg.fillRect(cardX,SY0+y+RC,4,rowH-RC*2);
                    gg.lineStyle(isHot||isPop?2.5:1.5,bordCol,isHot||isPop?0.90:0.55);
                    gg.strokeRoundedRect(cardX,SY0+y,cardW,rowH,RC);
                    gg.lineStyle(1,0xffffff,0.10); gg.strokeRoundedRect(cardX+2,SY0+y+2,cardW-4,rowH-4,RC-2);
                    _add(gg);

                    if(gp.tag){
                        const tagLabel=isHot?(CURRENT_LANG==="tr"?"BEST":"BEST VALUE"):(CURRENT_LANG==="tr"?"POPULER":"POPULAR");
                        const tagCol=isHot?0xcc5500:0xaa8800;
                        const tW=80,tH=20;
                        const tg2=G();
                        tg2.fillStyle(0x000000,0.40); tg2.fillRoundedRect(cardX+cardW-tW-1,SY0+y+1,tW,tH,{tl:0,tr:RC,bl:6,br:0});
                        tg2.fillStyle(tagCol,1); tg2.fillRoundedRect(cardX+cardW-tW,SY0+y,tW,tH,{tl:0,tr:RC,bl:6,br:0});
                        tg2.fillStyle(0xffffff,0.22); tg2.fillRoundedRect(cardX+cardW-tW,SY0+y,tW,tH*0.50,{tl:0,tr:RC-1,bl:0,br:0});
                        _add(tg2);
                        _add(T(cardX+cardW-tW/2,SY0+y+tH/2,(isHot?"★ ":"⭐ ")+tagLabel,{fontFamily:_F,fontSize:"9px",color:"#fff",stroke:"#000",strokeThickness:1}).setOrigin(0.5));
                    }

                    // ASSET — left side
                    const IMG_SZ=Math.min(rowH-10,106);
                    const IMG_X=cardX+8+IMG_SZ/2, IMG_Y=SY0+y+rowH/2;
                    if(gp.packImg && scene.textures.exists(gp.packImg)){
                        const gpImg=scene.add.image(IMG_X,IMG_Y,gp.packImg).setDisplaySize(IMG_SZ,IMG_SZ);
                        try{
                            const gl=scene.renderer&&scene.renderer.gl;
                            const _ts2=scene.textures.get(gp.packImg);
                            const _src2=_ts2&&_ts2.source&&_ts2.source[0];
                            if(gl&&_src2&&_src2.glTexture){
                                const aniso2=gl.getExtension("EXT_texture_filter_anisotropic")||gl.getExtension("MOZ_EXT_texture_filter_anisotropic")||gl.getExtension("WEBKIT_EXT_texture_filter_anisotropic");
                                gl.bindTexture(gl.TEXTURE_2D,_src2.glTexture);
                                gl.texParameteri(gl.TEXTURE_2D,gl.TEXTURE_WRAP_S,gl.CLAMP_TO_EDGE);
                                gl.texParameteri(gl.TEXTURE_2D,gl.TEXTURE_WRAP_T,gl.CLAMP_TO_EDGE);
                                gl.generateMipmap(gl.TEXTURE_2D);
                                gl.texParameteri(gl.TEXTURE_2D,gl.TEXTURE_MIN_FILTER,gl.LINEAR_MIPMAP_LINEAR);
                                gl.texParameteri(gl.TEXTURE_2D,gl.TEXTURE_MAG_FILTER,gl.LINEAR);
                                if(aniso2){const mA2=gl.getParameter(aniso2.MAX_TEXTURE_MAX_ANISOTROPY_EXT);gl.texParameterf(gl.TEXTURE_2D,aniso2.TEXTURE_MAX_ANISOTROPY_EXT,Math.min(8,mA2));}
                                gl.bindTexture(gl.TEXTURE_2D,null);
                            }
                        }catch(_){}
                        _add(gpImg);
                    }else{
                        _addCurrIcon(IMG_X,IMG_Y,"gold",IMG_SZ);
                    }

                    // ── TEXT + BUTTON ZONE ─────────────────────────────────
                    const TX2=cardX+8+IMG_SZ+10;
                    const BTN_W2=70, BTN_H2=rowH-16;
                    const BTN_CX2=cardX+cardW-6-BTN_W2/2, BTN_CY2=SY0+y+rowH/2;
                    const TXT_MAX_W2=BTN_CX2-BTN_W2/2-8-TX2;

                    const R1g=SY0+y+18, R2g=SY0+y+50, R3g=SY0+y+82;

                    _add(T(TX2,R1g,gp.title||"",{fontFamily:_F,fontSize:"11px",color:"#cc8833",stroke:"#000",strokeThickness:1}).setOrigin(0,0.5));

                    const totStr2=tot.toLocaleString();
                    const amtT2=T(TX2,R2g,totStr2,{fontFamily:_F,fontSize:"22px",color:"#ffffff",stroke:"#1a0600",strokeThickness:3}).setOrigin(0,0.5);
                    if(amtT2.width>TXT_MAX_W2-46) amtT2.setFontSize(18);
                    if(amtT2.width>TXT_MAX_W2-46) amtT2.setFontSize(15);
                    _add(amtT2);

                    // "GOLD" chip — beside amount
                    const chipG2=G();
                    const cpX2=TX2+amtT2.width+3, cpW2=42, cpH2=16;
                    chipG2.fillStyle(0x553300,1); chipG2.fillRoundedRect(cpX2,R2g-cpH2/2,cpW2,cpH2,5);
                    chipG2.fillStyle(0xffffff,0.12); chipG2.fillRoundedRect(cpX2,R2g-cpH2/2,cpW2,cpH2*0.5,{tl:5,tr:5,bl:0,br:0});
                    chipG2.lineStyle(1.5,0xffaa22,0.90); chipG2.strokeRoundedRect(cpX2,R2g-cpH2/2,cpW2,cpH2,5);
                    _add(chipG2);
                    _add(T(cpX2+cpW2/2,R2g,CURRENT_LANG==="tr"?"ALTIN":"GOLD",{fontFamily:_F,fontSize:"9px",color:"#ffdd88",stroke:"#000",strokeThickness:1}).setOrigin(0.5));

                    if(gp.bonus>0){
                        const bonG2=G();
                        const bnW2=Math.min(TXT_MAX_W2,96),bnH2=20;
                        bonG2.fillStyle(0x1a0e00,1); bonG2.fillRoundedRect(TX2,R3g-bnH2/2,bnW2,bnH2,6);
                        bonG2.fillStyle(0x3a2000,1); bonG2.fillRoundedRect(TX2,R3g-bnH2/2,bnW2,bnH2*0.5,{tl:6,tr:6,bl:0,br:0});
                        bonG2.lineStyle(1.5,0xffaa22,0.85); bonG2.strokeRoundedRect(TX2,R3g-bnH2/2,bnW2,bnH2,6);
                        _add(bonG2);
                        _add(T(TX2+bnW2/2,R3g,"+ "+gp.bonus.toLocaleString()+" BONUS",{fontFamily:_F,fontSize:"10px",color:"#ffcc44",stroke:"#000",strokeThickness:1}).setOrigin(0.5));
                    }

                    // BUY BUTTON — tall, gold style
                    const btnG2=G();
                    btnG2.fillStyle(0x000000,0.55); btnG2.fillRoundedRect(BTN_CX2-BTN_W2/2+3,BTN_CY2-BTN_H2/2+5,BTN_W2,BTN_H2,11);
                    btnG2.fillGradientStyle(0xdd9900,0xdd9900,0x664400,0x664400,1,1,1,1);
                    btnG2.fillRoundedRect(BTN_CX2-BTN_W2/2,BTN_CY2-BTN_H2/2,BTN_W2,BTN_H2,11);
                    btnG2.fillStyle(0xffffff,0.20); btnG2.fillRoundedRect(BTN_CX2-BTN_W2/2+4,BTN_CY2-BTN_H2/2+4,BTN_W2-8,BTN_H2*0.35,{tl:9,tr:9,bl:0,br:0});
                    btnG2.fillStyle(0xffcc44,0.30); btnG2.fillRoundedRect(BTN_CX2-BTN_W2/2,BTN_CY2+BTN_H2/2-5,BTN_W2,5,{tl:0,tr:0,bl:9,br:9});
                    btnG2.lineStyle(2.5,0xffee66,1.0); btnG2.strokeRoundedRect(BTN_CX2-BTN_W2/2,BTN_CY2-BTN_H2/2,BTN_W2,BTN_H2,11);
                    btnG2.lineStyle(1,0xffffff,0.20); btnG2.strokeRoundedRect(BTN_CX2-BTN_W2/2+2,BTN_CY2-BTN_H2/2+2,BTN_W2-4,BTN_H2-4,9);
                    _add(btnG2);
                    _addCurrIcon(BTN_CX2,BTN_CY2-10,"gold",22);
                    _add(T(BTN_CX2,BTN_CY2+12,gp.price,{fontFamily:_F,fontSize:"13px",color:"#ffffff",stroke:"#000",strokeThickness:2}).setOrigin(0.5));

                    _zone(0,y,PW-10,y+rowH,()=>{
                        if(window.Telegram?.WebApp?.openInvoice){
                            window.Telegram.WebApp.openInvoice("gold_"+i,(st)=>{
                                if(st==="paid"){PLAYER_GOLD+=tot;secureSet("nt_gold",PLAYER_GOLD);showBigReward(scene,cx,SY0+y+rowH/2,"gold",tot,D+10);scene.time.delayedCall(700,()=>_sh());}
                            });
                        }
                    });
                    y+=rowH+10;
                });


                totalH=y+10;
                break;
            }
        }
        // Update scroll max
        _scrollMax=Math.max(0,totalH-VIEW_H);
        _scrollTo(0);
        // Bekleyen scroll hedefi uygula (gold/gem pill tıklamasından gelir)
        if(_pendingScroll && _tab==="gems"){
            if(_pendingScroll==="gold" && _goldPacksY>0) _scrollTo(_goldPacksY-10);
            else if(_pendingScroll==="gem"  && _gemPacksY>0)  _scrollTo(_gemPacksY-10);
            _pendingScroll=null; // sadece ilk açılışta
        }
      } catch(err) {
        console.error("[NT] Shop render error:", err);
      }
    }

    _cleanupSc=()=>{
        try{scene.input.off("wheel",_shopWheelHandler);}catch(_){}
        try{maskGfx.destroy();}catch(_){}
        if(scene._offersCarHit){ try{scene._offersCarHit.destroy();}catch(_){} scene._offersCarHit=null; }
        _destroyScroll();
    };

    _sh();
}


// ═══════════════════════════════════════════════════════════════
// §7  POST-DEATH OFFER
// ═══════════════════════════════════════════════════════════════

function showDeathOffer(scene){
    // Removed — replaced by gem revive prompt shown before game over panel
    return;
    const s=_s();s.gm=(s.gm||0)+1;_sv(s);
    if(s.gm%3!==0)return;
    const D=920;
    const objs=[],A=o=>{objs.push(o);return o;};
    const _cl=()=>objs.forEach(o=>{try{o.destroy();}catch(_){}});
    scene.time.delayedCall(900,()=>{
        A(scene.add.rectangle(CX,H/2,W,H,0x000000,0.72).setDepth(D).setInteractive());
        const PW=270,PH=230,PY=H/2-PH/2;
        const pg=A(scene.add.graphics().setDepth(D+1));
        pg.fillStyle(0x080c16,0.98);pg.fillRoundedRect(CX-PW/2,PY,PW,PH,14);
        pg.lineStyle(3,0xff4488,0.9);pg.strokeRoundedRect(CX-PW/2,PY,PW,PH,14);
        pg.setScale(0.8).setAlpha(0);
        scene.tweens.add({targets:pg,scaleX:1,scaleY:1,alpha:1,duration:280,ease:"Back.easeOut"});
        A(scene.add.text(CX,PY+24,"POWER UP — NOT free though.",{fontFamily:_F,fontSize:"15px",color:"#ff88aa",stroke:"#000",strokeThickness:3}).setOrigin(0.5).setDepth(D+2));
        DEATH_OFFERS.forEach((of,i)=>{
            const cy=PY+52+i*50;
            const tc=of.tag?0xffaa00:0x4a3070;
            const og=A(scene.add.graphics().setDepth(D+2));
            og.fillStyle(0x0d1420,0.95);og.fillRoundedRect(CX-PW/2+8,cy-16,PW-16,38,6);
            og.lineStyle(1.5,tc,0.4);og.strokeRoundedRect(CX-PW/2+8,cy-16,PW-16,38,6);
            if(of.tag){og.fillStyle(tc,1);og.fillRoundedRect(CX+PW/2-68,cy-16,50,11,{tl:0,tr:6,bl:3,br:0});
                A(scene.add.text(CX+PW/2-43,cy-11,of.tag,{fontFamily:_F,fontSize:"5px",color:"#fff"}).setOrigin(0.5).setDepth(D+4));}
            A(scene.add.text(CX-PW/2+16,cy+2,of.gems+" + "+of.gold,{fontFamily:_F,fontSize:"11px",color:"#ddaacc",stroke:"#000",strokeThickness:1}).setOrigin(0,0.5).setDepth(D+3));
            if(scene.textures.exists("icon_gem"))  A(scene.add.image(CX-PW/2+16+56,cy+2,"icon_gem").setDisplaySize(14,14).setOrigin(0,0.5).setDepth(D+3));
            if(scene.textures.exists("icon_gold")) A(scene.add.image(CX-PW/2+16+74,cy+2,"icon_gold").setDisplaySize(14,14).setOrigin(0,0.5).setDepth(D+3));
            const bx=CX+PW/2-32;
            const bb=A(scene.add.graphics().setDepth(D+3));
            bb.fillStyle(0x550028,1);bb.fillRoundedRect(bx-20,cy-8,40,18,4);bb.lineStyle(1,0xff4488,0.8);bb.strokeRoundedRect(bx-20,cy-8,40,18,4);
            A(scene.add.text(bx,cy+1,"⭐"+of.stars,{fontFamily:_F,fontSize:"8px",color:"#fff",stroke:"#000",strokeThickness:1}).setOrigin(0.5).setDepth(D+4));
            A(scene.add.rectangle(bx,cy+1,40,18,0xffffff,0.001).setDepth(D+5).setInteractive({useHandCursor:true}))
            .on("pointerdown",()=>{
                if(window.Telegram?.WebApp?.openInvoice){window.Telegram.WebApp.openInvoice("death_"+i,(st)=>{
                    if(st==="paid"){showBigReward(scene,CX,cy,"gem",of.gems,D+10);PLAYER_GOLD+=of.gold;secureSet("nt_gold",PLAYER_GOLD);scene.time.delayedCall(800,_cl);}
                });}
            });
        });
        A(scene.add.text(CX,PY+PH-14,"No thanks",{fontFamily:_F,fontSize:"9px",color:"#556677",stroke:"#000",strokeThickness:1}).setOrigin(0.5).setDepth(D+3).setInteractive({useHandCursor:true})).on("pointerdown",_cl);
    });
}


// ═══════════════════════════════════════════════════════════════
// §8  DAILY MISSIONS — animated, balanced, professional
// Replaces old battle-pass; no paywall, all progression through play
// ═══════════════════════════════════════════════════════════════

// ── Date helpers (local date string used as daily key) ─────────
function _qDateStr(){ const d=new Date(); return d.getFullYear()+"-"+(d.getMonth()+1)+"-"+d.getDate(); }
function _qDayNum(){ return Math.floor((Date.now()-(new Date().getTimezoneOffset()*60000))/86400000); }
function _qMsToMidnight(){
    const d=new Date(); const nx=new Date(d); nx.setHours(24,0,0,0); return nx-d;
}

// ── Deterministic seeded RNG (so same day gives same quests) ──
function _qSeedRand(seed){
    let h = 2166136261 >>> 0;
    const s = String(seed);
    for(let i=0;i<s.length;i++){ h ^= s.charCodeAt(i); h = Math.imul(h, 16777619) >>> 0; }
    return function(){
        h += 0x6d2b79f5; h = Math.imul(h ^ (h>>>15), 1 | h);
        h ^= h + Math.imul(h ^ (h>>>7), 61 | h);
        return ((h ^ (h>>>14)) >>> 0) / 4294967296;
    };
}

// ── Daily quest generation ─────────────────────────────────────
// 5 standard game quests (social quests are in "Follow Us" tab separately)
function _qGenDaily(){
    const today = _qDateStr();
    const rnd = _qSeedRand("nt_quest_"+today);
    const poolE = QUEST_POOL.filter(q=>q.diff==="easy");
    const poolM = QUEST_POOL.filter(q=>q.diff==="medium");
    const poolH = QUEST_POOL.filter(q=>q.diff==="hard");
    const poolS = QUEST_POOL.filter(q=>q.diff==="special" && q.type!=="social");
    const pick = (arr)=>arr[Math.floor(rnd()*arr.length)];
    const e1 = pick(poolE);
    const m1 = pick(poolM);
    const out = [e1, m1, pick(poolH)];
    // 4th: second easy (different)
    const poolE2 = poolE.filter(q=>q.id !== e1.id);
    out.push(pick(poolE2.length ? poolE2 : poolE));
    // 5th: special every 3 days, otherwise second medium
    if(_qDayNum()%3===0 && poolS.length){
        out.push(pick(poolS));
    } else {
        const poolM2 = poolM.filter(q=>q.id !== m1.id);
        out.push(pick(poolM2.length ? poolM2 : poolM));
    }
    return out.map(q=>({ id:q.id, prog:0, claimed:false }));
}

function _qEnsureToday(){
    const s = _s();
    const today = _qDateStr();
    if(s.qd !== today || !Array.isArray(s.ql) || s.ql.length===0){
        s.qd = today;
        s.ql = _qGenDaily();
        _sv(s);
    }
    return s;
}

function _qDef(id){ return QUEST_POOL.find(x=>x.id===id); }
function _qIsDone(q){ const d=_qDef(q.id); return d && q.prog>=d.target; }

// ── Check if any quest is completed but not yet claimed ──────
// Used for the red "!" notification dot on the MISSIONS button
function _qHasUnclaimed(){
    const s = _qEnsureToday();
    return s.ql.some(q=> _qIsDone(q) && !q.claimed);
}
function _qHasPending(){
    const s = _qEnsureToday();
    return s.ql.some(q=> !_qIsDone(q));
}

// ── Progress tracking — called at game over ──────────────────
// kills/bosses/elites/games are CUMULATIVE across games today
// level/score/combo are BEST-OF-ANY-GAME today
function _qTrackGame(gs){
    if(!gs) return { completedNew: [] };
    const s = _qEnsureToday();
    const completedNew = [];
    s.ql.forEach(q=>{
        const d = _qDef(q.id); if(!d) return;
        const wasDone = q.prog >= d.target;
        if(wasDone) return;
        const kills  = gs.kills       || 0;
        const boss   = gs._bossKills  || 0;
        const elite  = gs._eliteKills || 0;
        const lvl    = gs.level       || 0;
        const scr    = gs.score       || 0;
        const cmb    = (gs.maxCombo!=null) ? gs.maxCombo : (gs.combo||0);
        switch(d.type){
            case "kills":  q.prog = Math.min(d.target, (q.prog||0) + kills);  break;
            case "bosses": q.prog = Math.min(d.target, (q.prog||0) + boss);   break;
            case "elites": q.prog = Math.min(d.target, (q.prog||0) + elite);  break;
            case "games":  q.prog = Math.min(d.target, (q.prog||0) + 1);      break;
            case "level":  q.prog = Math.min(d.target, Math.max(q.prog||0, lvl)); break;
            case "score":  q.prog = Math.min(d.target, Math.max(q.prog||0, scr)); break;
            case "combo":  q.prog = Math.min(d.target, Math.max(q.prog||0, cmb)); break;
        }
        if(q.prog >= d.target && !wasDone) completedNew.push(d);
    });
    _sv(s);
    return { completedNew };
}

// ── Claim reward: gold + player-XP + (rare) gems ──────────────
function _qClaim(scene, q, xIcon, yIcon, depth){
    const d = _qDef(q.id); if(!d) return false;
    if(!_qIsDone(q) || q.claimed) return false;
    const s = _s();
    const qRef = s.ql.find(x=>x.id===q.id); if(!qRef) return false;
    // [BUG FIX] Önce storage'a yaz, SONRA ödülü ver — spam veya çift çağrıda ikinci geçiş engellenir
    if(qRef.claimed) return false;   // storage seviyesinde ikinci kontrol
    qRef.claimed = true;
    q.claimed    = true;             // lokal closure objesini de güncelle
    _sv(s);

    const r = d.reward || {};
    let anims = 0;
    if(r.gold){
        PLAYER_GOLD += r.gold; secureSet("nt_gold", PLAYER_GOLD);
        scene.time.delayedCall(anims*180, ()=> showBigRewardVisualOnly(scene, xIcon, yIcon, "gold", r.gold, depth+10));
        anims++;
    }
    if(r.gem){
        addGems(r.gem);
        scene.time.delayedCall(anims*220, ()=> showBigRewardVisualOnly(scene, xIcon, yIcon-18, "gem", r.gem, depth+10));
        anims++;
    }
    if(r.xp && typeof _plvAddXP==="function"){
        try{ _plvAddXP(r.xp); }catch(e){ console.warn("[NT] xp err", e); }
    }
    NT_SFX.play("upgrade_select");
    return true;
}

function showMissions(scene){
    let _cleanupMQ=()=>{};
    const {A,close,contentTop,contentBot,CX:cx,depth:D,PW}
        =NT_OpenPopup(scene,"mm_panel",330,CURRENT_LANG==="tr"?"GUNLUK GOREVLER":"DAILY MISSIONS",312,20,()=>_cleanupMQ());

    // ── TAB BAR ──────────────────────────────────────────────────────
    let _activeTab="missions"; // "missions" | "follow"
    const tabY=contentTop+18;
    const tabW=(PW-28)/2;
    const tab1X=cx-tabW-2, tab2X=cx+2;
    const tabH=36;

    const tabBg1=A(scene.add.graphics().setDepth(D+3));
    const tabBg2=A(scene.add.graphics().setDepth(D+3));
    const tabTxt1=A(scene.add.text(tab1X+tabW/2,tabY,
        CURRENT_LANG==="tr"?"GÖREVLER":"QUESTS",
        {fontFamily:_F,fontSize:"17px",color:"#ffffff",stroke:"#000",strokeThickness:3}
    ).setOrigin(0.5).setDepth(D+5));
    const tabTxt2=A(scene.add.text(tab2X+tabW/2,tabY,
        CURRENT_LANG==="tr"?"TAKİP ET":"FOLLOW US",
        {fontFamily:_F,fontSize:"17px",color:"#888888",stroke:"#000",strokeThickness:3}
    ).setOrigin(0.5).setDepth(D+5));

    function _drawTabs(){
        tabBg1.clear(); tabBg2.clear();
        const on1=(_activeTab==="missions");
        // Leaderboard theme: red active, dark grey inactive
        tabBg1.fillStyle(on1?0xcc0000:0x1a1a1a,1);
        tabBg1.fillRoundedRect(tab1X,tabY-tabH/2,tabW,tabH,{tl:8,tr:0,bl:0,br:0});
        if(on1){tabBg1.fillStyle(0xffffff,0.15);tabBg1.fillRoundedRect(tab1X+2,tabY-tabH/2+3,tabW-4,tabH/2-4,4);}
        tabBg1.lineStyle(on1?2.5:1,on1?0xff3333:0x444444,on1?0.95:0.45);
        tabBg1.strokeRoundedRect(tab1X,tabY-tabH/2,tabW,tabH,{tl:8,tr:0,bl:0,br:0});
        tabTxt1.setColor(on1?"#ffffff":"#666666");
        tabBg2.fillStyle(!on1?0xcc0000:0x1a1a1a,1);
        tabBg2.fillRoundedRect(tab2X,tabY-tabH/2,tabW,tabH,{tl:0,tr:8,bl:0,br:0});
        if(!on1){tabBg2.fillStyle(0xffffff,0.15);tabBg2.fillRoundedRect(tab2X+2,tabY-tabH/2+3,tabW-4,tabH/2-4,4);}
        tabBg2.lineStyle(!on1?2.5:1,!on1?0xff3333:0x444444,!on1?0.95:0.45);
        tabBg2.strokeRoundedRect(tab2X,tabY-tabH/2,tabW,tabH,{tl:0,tr:8,bl:0,br:0});
        tabTxt2.setColor(!on1?"#ffffff":"#666666");
    }
    _drawTabs();
    A(scene.add.rectangle(tab1X+tabW/2,tabY,tabW,tabH,0xffffff,0.001).setDepth(D+6).setInteractive({useHandCursor:true}))
        .on("pointerdown",()=>{if(_activeTab==="missions")return;NT_SFX.play("menu_click");_activeTab="missions";_drawTabs();_showContent();});
    A(scene.add.rectangle(tab2X+tabW/2,tabY,tabW,tabH,0xffffff,0.001).setDepth(D+6).setInteractive({useHandCursor:true}))
        .on("pointerdown",()=>{if(_activeTab==="follow")return;NT_SFX.play("menu_click");_activeTab="follow";_drawTabs();_showContent();});

    // ── SHARED SCROLL/MASK SETUP ──────────────────────────────────────
    const contentAreaY=tabY+tabH/2+2;
    const VIEW_H=contentBot-contentAreaY-4;
    const VPORT_X=cx-PW/2+10, VPORT_W=PW-20;

    const maskGfx=scene.add.graphics().setDepth(D+1);
    maskGfx.fillStyle(0xffffff,1);
    maskGfx.fillRect(VPORT_X,contentAreaY,VPORT_W,VIEW_H);
    const geomMask=maskGfx.createGeometryMask();
    maskGfx.setVisible(false);

    let _scrollCont=null, _scrollY=0, _scrollMax=0;
    let _dragStartY=0, _dragStartSY=0, _isDragging=false;
    let _scrollHit=null, _clockEvt=null;
    // Extra scene-level objects that aren't in the container
    let _extraObjs=[];
    const _zones=[];

    function _scrollTo(y){
        _scrollY=Math.max(0,Math.min(_scrollMax,y));
        if(_scrollCont) _scrollCont.y=-_scrollY;
    }
    const _wheelHandler=(pointer,gameObjects,dx,dy)=>{_scrollTo(_scrollY+dy*0.5);};
    scene.input.on("wheel",_wheelHandler);

    function _destroyContent(){
        // Destroy container and all children
        if(_scrollCont){try{_scrollCont.destroy();}catch(_){}_scrollCont=null;}
        // Destroy scroll hit zone
        if(_scrollHit){try{_scrollHit.destroy();}catch(_){}_scrollHit=null;}
        // Destroy orphaned scene-level objects (headers etc.)
        _extraObjs.forEach(o=>{try{o.destroy();}catch(_){}});
        _extraObjs=[];
        // Destroy clock
        if(_clockEvt){try{_clockEvt.remove(false);}catch(_){}_clockEvt=null;}
        _zones.length=0; _scrollY=0; _scrollMax=0;
    }

    function _showContent(){
        _destroyContent();
        if(_activeTab==="missions") _buildMissionsTab();
        else _buildFollowTab();
    }

    // ── TAB 1: MISSIONS ──────────────────────────────────────────────
    function _buildMissionsTab(){
        const SY0=contentAreaY;
        const s=_qEnsureToday();
        const quests=s.ql.slice();

        // Header bar — stored in _extraObjs for cleanup
        const hdrH=48;
        const hdrG=scene.add.graphics().setDepth(D+3);
        hdrG.fillStyle(0x1a0000,1);hdrG.fillRoundedRect(cx-PW/2+10,SY0+2,PW-20,hdrH,6);
        hdrG.fillStyle(0xffffff,0.06);hdrG.fillRoundedRect(cx-PW/2+12,SY0+4,PW-24,hdrH*0.4,4);
        hdrG.lineStyle(2.5,0xcc0000,0.80);hdrG.strokeRoundedRect(cx-PW/2+10,SY0+2,PW-20,hdrH,6);
        _extraObjs.push(hdrG);

        const doneCount=quests.filter(q=>_qIsDone(q)).length;
        const totalCount=quests.length;
        const cmpTxt=scene.add.text(cx-PW/2+18,SY0+2+17,
            (CURRENT_LANG==="tr"?"TAMAMLANAN: ":"COMPLETED: ")+doneCount+" / "+totalCount,
            {fontFamily:_F,fontSize:"15px",color:"#ffffff",stroke:"#000",strokeThickness:3}
        ).setOrigin(0,0.5).setDepth(D+4).setResolution(2);
        _extraObjs.push(cmpTxt);

        const clockTxt=scene.add.text(cx+PW/2-18,SY0+2+17,"",
            {fontFamily:_F,fontSize:"13px",color:"#66bbee",stroke:"#000",strokeThickness:2}
        ).setOrigin(1,0.5).setDepth(D+4);
        _extraObjs.push(clockTxt);
        const _updClock=()=>{
            const ms=_qMsToMidnight();
            const h=Math.floor(ms/3600000),m=Math.floor((ms%3600000)/60000);
            if(clockTxt.scene) clockTxt.setText((CURRENT_LANG==="tr"?"YEN: ":"RST: ")+h+"h "+m+"m");
        };
        _updClock();
        _clockEvt=scene.time.addEvent({delay:30000,loop:true,callback:_updClock});

        // Progress bar
        const pbX=cx-PW/2+18,pbW=PW-36,pbY=SY0+2+36,pbH=6;
        const pbBg=scene.add.graphics().setDepth(D+3);
        pbBg.fillStyle(0x111e30,1);pbBg.fillRoundedRect(pbX,pbY,pbW,pbH,2);
        pbBg.lineStyle(1,0x2a4060,0.5);pbBg.strokeRoundedRect(pbX,pbY,pbW,pbH,2);
        _extraObjs.push(pbBg);
        const pbFill=scene.add.graphics().setDepth(D+4);
        _extraObjs.push(pbFill);
        const progRatio=totalCount>0?doneCount/totalCount:0;
        const _pb={v:0};
        scene.tweens.add({targets:_pb,v:progRatio,duration:600,delay:150,ease:"Quad.easeOut",
            onUpdate:()=>{
                if(!pbFill.scene)return;
                pbFill.clear();if(_pb.v<=0)return;
                pbFill.fillStyle(_pb.v>=1?0x44dd66:0x44aaff,0.95);
                pbFill.fillRoundedRect(pbX,pbY,Math.max(pbH,pbW*_pb.v),pbH,2);
            }
        });

        const listSY0=SY0+hdrH+6;
        _scrollCont=A(scene.add.container(0,0).setDepth(D+4));
        _scrollCont.setMask(geomMask);

        const ROW_H=132,ROW_GAP=8,rowStart=listSY0+4;

        quests.forEach((q,i)=>{
            const d=_qDef(q.id);if(!d)return;
            const diffInfo=QUEST_DIFF[d.diff]||QUEST_DIFF.easy;
            const ry=rowStart+i*(ROW_H+ROW_GAP);
            const done=_qIsDone(q),claimed=q.claimed,avail=done&&!claimed;
            const pFrac=Math.min(1,(q.prog||0)/d.target);

            // Row background
            const rg=scene.add.graphics();
            rg.fillStyle(claimed?0x0a1d10:avail?0x1a0808:0x111111,0.97);
            rg.fillRoundedRect(cx-PW/2+12,ry,PW-24,ROW_H,8);
            rg.lineStyle(avail?2.5:1.5,claimed?0x44cc66:avail?0xcc0000:0x333333,claimed?0.65:avail?0.90:0.35);
            rg.strokeRoundedRect(cx-PW/2+12,ry,PW-24,ROW_H,8);
            _scrollCont.add(rg);

            // Difficulty ribbon
            const rib=scene.add.graphics();
            rib.fillStyle(diffInfo.col,1);rib.fillRoundedRect(cx-PW/2+12,ry,62,20,5);
            rib.fillStyle(0xffffff,0.18);rib.fillRoundedRect(cx-PW/2+14,ry+2,58,8,3);
            _scrollCont.add(rib);
            _scrollCont.add(scene.add.text(cx-PW/2+43,ry+10,CURRENT_LANG==="tr"?diffInfo.labelTR:diffInfo.label,
                {fontFamily:_F,fontSize:"11px",color:"#ffffff",stroke:"#000",strokeThickness:2}).setOrigin(0.5).setResolution(2));

            // Left badge (✓ only when claimable)
            const exX=cx-PW/2+18,exY=ry+52;
            if(avail){
                const exG=scene.add.graphics();
                exG.fillStyle(0x22cc66,0.85);
                exG.fillCircle(exX,exY,9);
                exG.lineStyle(1.5,0xffffff,0.5);exG.strokeCircle(exX,exY,9);
                _scrollCont.add(exG);
                const exT=scene.add.text(exX,exY,"✓",
                    {fontFamily:_F,fontSize:"13px",color:"#ffffff",stroke:"#000",strokeThickness:2,fontStyle:"bold"}).setOrigin(0.5);
                _scrollCont.add(exT);
            }

            // Quest icon - solid filled silhouette style (larger)
            const iconShadow=scene.add.text(cx-PW/2+43,ry+54,d.icon,{fontFamily:_F,fontSize:"30px",color:"#000000"}).setOrigin(0.5).setAlpha(0.6);
            _scrollCont.add(iconShadow);
            const iconTxt=scene.add.text(cx-PW/2+42,ry+52,d.icon,{fontFamily:_F,fontSize:"30px"}).setOrigin(0.5);
            _scrollCont.add(iconTxt);

            // Name, desc, progress
            const txtX=cx-PW/2+62;
            _scrollCont.add(scene.add.text(txtX,ry+24,CURRENT_LANG==="tr"?d.nameTR:d.name,
                {fontFamily:_F,fontSize:"17px",color:claimed?"#66cc88":"#ffffff",stroke:"#000",strokeThickness:3}).setOrigin(0,0).setResolution(2));
            const descStr=CURRENT_LANG==="tr"?(d.descTR||""):(d.desc||"");
            if(descStr) _scrollCont.add(scene.add.text(txtX,ry+48,descStr,
                {fontFamily:_F,fontSize:"12px",color:claimed?"#557766":"#ffffff",stroke:"#000",strokeThickness:3,wordWrap:{width:148},maxLines:2}).setOrigin(0,0).setResolution(2));
            _scrollCont.add(scene.add.text(txtX,ry+78,Math.min(q.prog,d.target).toLocaleString()+" / "+d.target.toLocaleString(),
                {fontFamily:_F,fontSize:"13px",color:claimed?"#5a8a6a":avail?diffInfo.colStr:"#8899aa",stroke:"#000",strokeThickness:2}).setOrigin(0,0).setResolution(2));

            // Progress bar
            const barX=txtX,barY=ry+96,barW=150,barH=9;
            const bbG=scene.add.graphics();
            bbG.fillStyle(0x111e30,1);bbG.fillRoundedRect(barX,barY,barW,barH,2);
            bbG.lineStyle(1,0x2a4060,0.5);bbG.strokeRoundedRect(barX,barY,barW,barH,2);
            _scrollCont.add(bbG);
            if(pFrac>0){
                const bfG=scene.add.graphics();
                bfG.fillStyle(claimed?0x44aa66:diffInfo.col,0.92);
                bfG.fillRoundedRect(barX,barY,Math.max(barH,barW*pFrac),barH,2);
                _scrollCont.add(bfG);
            }

            // Reward pills (right side)
            const rewX=cx+PW/2-14;
            let rewY=ry+14;
            const r=d.reward;
            if(r.gold&&r.gold>0){
                const pg=scene.add.graphics();
                pg.fillStyle(0x1a0800,1);pg.fillRoundedRect(rewX-78,rewY,78,30,7);
                pg.lineStyle(2,0xcc0000,0.90);pg.strokeRoundedRect(rewX-78,rewY,78,30,7);
                pg.fillStyle(0xffffff,0.10);pg.fillRoundedRect(rewX-76,rewY+2,74,11,4);
                _scrollCont.add(pg);
                _scrollCont.add(scene.add.text(rewX-78+8,rewY+15,"+"+r.gold,
                    {fontFamily:_F,fontSize:"14px",color:"#ffffff",stroke:"#000",strokeThickness:2}).setOrigin(0,0.5).setResolution(2));
                if(scene.textures.exists("icon_gold"))
                    _scrollCont.add(scene.add.image(rewX-14,rewY+15,"icon_gold").setDisplaySize(24,24).setOrigin(0.5));
                rewY+=36;
            }
            if(r.xp){
                const pg=scene.add.graphics();
                pg.fillStyle(0x1a1a1a,1);pg.fillRoundedRect(rewX-72,rewY,72,30,7);
                pg.lineStyle(2,0x888888,0.70);pg.strokeRoundedRect(rewX-72,rewY,72,30,7);
                pg.fillStyle(0xffffff,0.10);pg.fillRoundedRect(rewX-70,rewY+2,68,11,4);
                _scrollCont.add(pg);
                _scrollCont.add(scene.add.text(rewX-36,rewY+15,"+"+r.xp+" XP",
                    {fontFamily:_F,fontSize:"13px",color:"#cccccc",stroke:"#000",strokeThickness:2}).setOrigin(0.5,0.5).setResolution(2));
                rewY+=34;
            }
            if(r.gem&&r.gem>0){
                const pg=scene.add.graphics();
                pg.fillStyle(0x1a0014,1);pg.fillRoundedRect(rewX-78,rewY,78,30,7);
                pg.lineStyle(2,0xcc0000,0.90);pg.strokeRoundedRect(rewX-78,rewY,78,30,7);
                pg.fillStyle(0xffffff,0.10);pg.fillRoundedRect(rewX-76,rewY+2,74,11,4);
                _scrollCont.add(pg);
                _scrollCont.add(scene.add.text(rewX-78+8,rewY+15,"+"+r.gem,
                    {fontFamily:_F,fontSize:"14px",color:"#ffffff",stroke:"#000",strokeThickness:2}).setOrigin(0,0.5).setResolution(2));
                if(scene.textures.exists("icon_gem"))
                    _scrollCont.add(scene.add.image(rewX-14,rewY+15,"icon_gem").setDisplaySize(24,24).setOrigin(0.5));
                rewY+=36;
            }

            // Right side action
            const btnW=82,btnH=28;
            const btnX=cx+PW/2-14-btnW,btnY=ry+ROW_H-btnH-5;
            if(avail){
                const cbg=scene.add.graphics();
                cbg.fillStyle(0xcc0000,1);cbg.fillRoundedRect(btnX,btnY,btnW,btnH,8);
                cbg.fillStyle(0xffffff,0.22);cbg.fillRoundedRect(btnX+2,btnY+2,btnW-4,btnH*0.42,{tl:6,tr:6,bl:0,br:0});
                cbg.lineStyle(2.5,0xff4444,0.80);cbg.strokeRoundedRect(btnX,btnY,btnW,btnH,8);
                _scrollCont.add(cbg);
                const cTxt=scene.add.text(btnX+btnW/2,btnY+btnH/2,CURRENT_LANG==="tr"?"ÖDÜL AL":"CLAIM",
                    {fontFamily:_F,fontSize:"14px",color:"#ffffff",stroke:"#000",strokeThickness:3}).setOrigin(0.5).setResolution(2);
                _scrollCont.add(cTxt);
                scene.tweens.add({targets:[cbg,cTxt],alpha:{from:1,to:0.70},yoyo:true,repeat:-1,duration:650,ease:"Sine.easeInOut"});
                _zones.push({
                    x1:btnX,x2:btnX+btnW,y1:btnY-SY0,y2:btnY-SY0+btnH,
                    fn:(()=>{
                        let _claimFired = false; // [BUG FIX] spam koruması — ilk tıkta kilit
                        return ()=>{
                            if(_claimFired) return; // ikinci tık → anında iptal
                            _claimFired = true;
                            // Ödül animasyonu her zaman popup ortasında görünür — scroll pozisyonundan bağımsız
                            const _rewardX = cx;
                            const _rewardY = contentTop + (contentBot - contentTop) / 2;
                            _qClaim(scene,q,_rewardX,_rewardY,D);
                            scene.time.delayedCall(300,()=>{close();showMissions(scene);});
                        };
                    })()
                });
            } else if(claimed){
                const bgG=scene.add.graphics();
                bgG.fillStyle(0x1a3a22,1);bgG.fillRoundedRect(btnX,btnY,btnW,btnH,8);
                bgG.fillStyle(0xffffff,0.12);bgG.fillRoundedRect(btnX+2,btnY+2,btnW-4,btnH*0.42,{tl:6,tr:6,bl:0,br:0});
                bgG.lineStyle(2.5,0x44ee66,0.85);bgG.strokeRoundedRect(btnX,btnY,btnW,btnH,8);
                _scrollCont.add(bgG);
                _scrollCont.add(scene.add.text(btnX+btnW/2,btnY+btnH/2,"✓ "+(CURRENT_LANG==="tr"?"ALINDI":"CLAIMED"),
                    {fontFamily:_F,fontSize:"13px",color:"#ffffff",stroke:"#000",strokeThickness:3}).setOrigin(0.5).setResolution(2));
            } else {
                _scrollCont.add(scene.add.text(cx+PW/2-22-36,ry+ROW_H-16,Math.floor(pFrac*100)+"%",
                    {fontFamily:_F,fontSize:"12px",color:"#8899aa",stroke:"#000",strokeThickness:2}).setOrigin(0.5));
            }

            rg.setAlpha(0);
            scene.tweens.add({targets:rg,alpha:1,duration:200,delay:60+i*70,ease:"Quad.easeOut"});
        });

        // Footer note
        const hasSpecial=quests.some(q=>{const d=_qDef(q.id);return d&&d.diff==="special";});
        if(!hasSpecial){
            const fY=rowStart+quests.length*(ROW_H+ROW_GAP)+4;
            const _ntG=scene.add.graphics();
            _ntG.fillStyle(0x060c1a,1);_ntG.fillRoundedRect(cx-PW/2+10,fY+4,PW-20,32,6);
            _ntG.lineStyle(1.5,0x2244aa,0.4);_ntG.strokeRoundedRect(cx-PW/2+10,fY+4,PW-20,32,6);
            _scrollCont.add(_ntG);
            _scrollCont.add(scene.add.text(cx,fY+20,
                CURRENT_LANG==="tr"?"💎 NOThing özel... henüz. (Her 3 günde bir gelir)":"💎 NOThing special... yet. (Every 3 days)",
                {fontFamily:_F,fontSize:"13px",color:"#cce0ff",stroke:"#000",strokeThickness:3}).setOrigin(0.5).setResolution(2));
        }

        const totalH=8+quests.length*(ROW_H+ROW_GAP)+30;
        _scrollMax=Math.max(0,totalH-(VIEW_H-(hdrH+6)));
        _scrollTo(0);

        _scrollHit=A(scene.add.rectangle(cx,contentAreaY+VIEW_H/2,VPORT_W,VIEW_H,0xffffff,0.001).setDepth(D+7).setInteractive({draggable:false}));
        _scrollHit.on("pointerdown",(p)=>{_isDragging=false;_dragStartY=p.y;_dragStartSY=_scrollY;});
        _scrollHit.on("pointermove",(p)=>{
            if(!p.isDown)return;
            if(Math.abs(p.y-_dragStartY)>6)_isDragging=true;
            if(_isDragging)_scrollTo(_dragStartSY-(p.y-_dragStartY));
        });
        _scrollHit.on("pointerup",(p)=>{
            if(!_isDragging){
                const lx=p.x,ly=p.y-SY0+_scrollY;
                for(const z of _zones){if(lx>=z.x1&&lx<=z.x2&&ly>=z.y1&&ly<=z.y2){z.fn();break;}}
            }
            _isDragging=false;
        });
    }

    // ── TAB 2: FOLLOW US ─────────────────────────────────────────────
    function _buildFollowTab(){
        const SY0=contentAreaY;
        const socialQuests=QUEST_POOL.filter(q=>q.type==="social");
        const s2=_s();

        _scrollCont=A(scene.add.container(0,0).setDepth(D+4));
        _scrollCont.setMask(geomMask);

        // Header
        const hdrG=scene.add.graphics();
        hdrG.fillStyle(0x1a0000,0.98);hdrG.fillRoundedRect(cx-PW/2+10,SY0+4,PW-20,48,6);
        hdrG.fillStyle(0xffffff,0.06);hdrG.fillRoundedRect(cx-PW/2+12,SY0+6,PW-24,20,4);
        hdrG.lineStyle(2.5,0xcc0000,0.80);hdrG.strokeRoundedRect(cx-PW/2+10,SY0+4,PW-20,48,6);
        _scrollCont.add(hdrG);
        _scrollCont.add(scene.add.text(cx,SY0+22,
            CURRENT_LANG==="tr"?"X  TAKİP ET — NF ELMAS KAZAN":"X  FOLLOW — EARN NF GEMS",
            {fontFamily:_F,fontSize:"16px",color:"#ffffff",stroke:"#000",strokeThickness:3}).setOrigin(0.5).setResolution(2));
        _scrollCont.add(scene.add.text(cx,SY0+40,
            CURRENT_LANG==="tr"?"Her hesap kalıcı olarak 1 kez tamamlanır":"Each account completes permanently once",
            {fontFamily:_F,fontSize:"11px",color:"#888888",stroke:"#000",strokeThickness:2}).setOrigin(0.5));

        const ROW_H=110,ROW_GAP=8,rowStart=SY0+60;

        socialQuests.forEach((d,i)=>{
            const isDone=s2._socialDone&&s2._socialDone[d.id];
            const ry=rowStart+i*(ROW_H+ROW_GAP);

            // Row bg
            const rg=scene.add.graphics();
            rg.fillStyle(isDone?0x0a1d10:0x111111,0.97);
            rg.fillRoundedRect(cx-PW/2+12,ry,PW-24,ROW_H,8);
            rg.lineStyle(2,isDone?0x44dd66:0xcc0000,isDone?0.55:0.70);
            rg.strokeRoundedRect(cx-PW/2+12,ry,PW-24,ROW_H,8);
            _scrollCont.add(rg);

            // 𝕏 glow circle on left
            const gX=cx-PW/2+36,gY=ry+ROW_H/2;
            const gCirc=scene.add.graphics();
            gCirc.fillStyle(isDone?0x224422:0x2a0000,0.95);
            gCirc.fillCircle(gX,gY,23);
            gCirc.lineStyle(2.5,isDone?0x44dd66:0xcc0000,0.85);
            gCirc.strokeCircle(gX,gY,23);
            _scrollCont.add(gCirc);
            _scrollCont.add(scene.add.text(gX,gY,isDone?"✓":"𝕏",
                {fontFamily:_F,fontSize:"18px",color:isDone?"#44dd66":"#ffffff",stroke:"#000",strokeThickness:3}).setOrigin(0.5));
            if(!isDone) scene.tweens.add({targets:gCirc,alpha:{from:0.75,to:1},yoyo:true,repeat:-1,duration:900,ease:"Sine.easeInOut"});

            // Text info
            const txX=cx-PW/2+66;
            _scrollCont.add(scene.add.text(txX,ry+16,CURRENT_LANG==="tr"?d.nameTR:d.name,
                {fontFamily:_F,fontSize:"17px",color:isDone?"#66dd88":"#ffffff",stroke:"#000",strokeThickness:3}).setOrigin(0,0).setResolution(2));
            _scrollCont.add(scene.add.text(txX,ry+35,CURRENT_LANG==="tr"?(d.descTR||""):(d.desc||""),
                {fontFamily:_F,fontSize:"11px",color:isDone?"#447755":"#aa88dd",stroke:"#000",strokeThickness:2,wordWrap:{width:150}}).setOrigin(0,0));

            // Gem reward pill
            const rewX=cx+PW/2-14;
            if(d.reward&&d.reward.gem){
                const pg=scene.add.graphics();
                pg.fillStyle(0x1a0000,1);pg.fillRoundedRect(rewX-78,ry+14,78,32,7);
                pg.lineStyle(2.5,isDone?0x44dd66:0xcc0000,0.90);pg.strokeRoundedRect(rewX-78,ry+14,78,32,7);
                pg.fillStyle(0xffffff,0.12);pg.fillRoundedRect(rewX-76,ry+16,74,12,4);
                _scrollCont.add(pg);
                _scrollCont.add(scene.add.text(rewX-78+8,ry+30,"+"+d.reward.gem,
                    {fontFamily:_F,fontSize:"15px",color:isDone?"#66dd88":"#ffffff",stroke:"#000",strokeThickness:2}).setOrigin(0,0.5).setResolution(2));
                if(scene.textures.exists("icon_gem"))
                    _scrollCont.add(scene.add.image(rewX-16,ry+30,"icon_gem").setDisplaySize(26,26).setOrigin(0.5));
            }

            // Follow button OR done badge
            const btnW=100,btnH=32;
            const btnX=cx+PW/2-14-btnW,btnY=ry+ROW_H-btnH-6;
            if(!isDone){
                // Follow button
                const fbX=btnX,fbW=btnW;
                const sbg=scene.add.graphics();
                sbg.fillStyle(0xcc0000,1);sbg.fillRoundedRect(fbX,btnY,fbW,btnH,8);
                sbg.lineStyle(2.5,0xff4444,0.80);sbg.strokeRoundedRect(fbX,btnY,fbW,btnH,8);
                sbg.fillStyle(0xffffff,0.18);sbg.fillRoundedRect(fbX+2,btnY+2,fbW-4,btnH*0.40,{tl:6,tr:6,bl:0,br:0});
                _scrollCont.add(sbg);
                const sTxt=scene.add.text(fbX+fbW/2,btnY+btnH/2,
                    CURRENT_LANG==="tr"?"TAKİP ET":"FOLLOW",
                    {fontFamily:_F,fontSize:"15px",color:"#ffffff",stroke:"#000",strokeThickness:3,fontStyle:"bold"}).setOrigin(0.5);
                _scrollCont.add(sTxt);
                scene.tweens.add({targets:[sbg,sTxt],alpha:{from:1,to:0.65},yoyo:true,repeat:-1,duration:700,ease:"Sine.easeInOut"});

                _zones.push({
                    x1:btnX,x2:btnX+btnW,y1:btnY-SY0,y2:btnY-SY0+btnH,
                    fn:()=>{
                        try{window.open(d.socialURL||"https://x.com","_blank");}catch(_){}
                        const sv=_s();
                        if(!sv._socialDone)sv._socialDone={};
                        sv._socialDone[d.id]=true;
                        if(d.reward&&d.reward.gem)addGems(d.reward.gem);
                        _sv(sv);
                        NT_SFX.play("menu_click");
                        showBigReward(scene,cx,contentAreaY+120,"gem",d.reward?d.reward.gem:5,D+10);
                        scene.time.delayedCall(300,()=>{close();showMissions(scene);});
                    }
                });
            } else {
                const bgG=scene.add.graphics();
                bgG.fillStyle(0x1a3a22,1);bgG.fillRoundedRect(btnX,btnY,btnW,btnH,8);
                bgG.fillStyle(0xffffff,0.12);bgG.fillRoundedRect(btnX+2,btnY+2,btnW-4,btnH*0.42,{tl:6,tr:6,bl:0,br:0});
                bgG.lineStyle(2.5,0x44ee66,0.85);bgG.strokeRoundedRect(btnX,btnY,btnW,btnH,8);
                _scrollCont.add(bgG);
                _scrollCont.add(scene.add.text(btnX+btnW/2,btnY+btnH/2,"✓ "+(CURRENT_LANG==="tr"?"TAMAM":"DONE"),
                    {fontFamily:_F,fontSize:"14px",color:"#ffffff",stroke:"#000",strokeThickness:3}).setOrigin(0.5).setResolution(2));
            }

            rg.setAlpha(0);
            scene.tweens.add({targets:rg,alpha:1,duration:220,delay:80+i*100,ease:"Quad.easeOut"});
        });

        const totalH=8+socialQuests.length*(ROW_H+ROW_GAP)+20;
        _scrollMax=Math.max(0,totalH-VIEW_H);
        _scrollTo(0);

        _scrollHit=A(scene.add.rectangle(cx,contentAreaY+VIEW_H/2,VPORT_W,VIEW_H,0xffffff,0.001).setDepth(D+7).setInteractive({draggable:false}));
        _scrollHit.on("pointerdown",(p)=>{_isDragging=false;_dragStartY=p.y;_dragStartSY=_scrollY;});
        _scrollHit.on("pointermove",(p)=>{
            if(!p.isDown)return;
            if(Math.abs(p.y-_dragStartY)>6)_isDragging=true;
            if(_isDragging)_scrollTo(_dragStartSY-(p.y-_dragStartY));
        });
        _scrollHit.on("pointerup",(p)=>{
            if(!_isDragging){
                const lx=p.x,ly=p.y-SY0+_scrollY;
                for(const z of _zones){if(lx>=z.x1&&lx<=z.x2&&ly>=z.y1&&ly<=z.y2){z.fn();break;}}
            }
            _isDragging=false;
        });
    }

    _showContent();

    _cleanupMQ=()=>{
        try{scene.input.off("wheel",_wheelHandler);}catch(_){}
        try{if(_clockEvt)_clockEvt.remove(false);}catch(_){}
        try{maskGfx.destroy();}catch(_){}
        _extraObjs.forEach(o=>{try{o.destroy();}catch(_){}});
        _extraObjs=[];
        if(_scrollCont){try{_scrollCont.destroy();}catch(_){}}
        if(_scrollHit){try{_scrollHit.destroy();}catch(_){}}
    };
}

