        const {A,close,contentTop,contentBot,TX,CX,PW,depth}
            = NT_OpenPopup(this,"mm_panel",330,CURRENT_LANG==="tr"?"❓  NASIL OYNANIR":"❓  HOW TO PLAY",368,20,undefined,"howto");
