                    if(typeof NT_VL!=="undefined"){
                        const _ct3n=_prevComboN<3&&gs.combo>=3, _ct8n=_prevComboN<8&&gs.combo>=8, _ct13n=_prevComboN<13&&gs.combo>=13;
                        if(_ct3n||_ct8n||_ct13n) NT_VL.comboVoice(_S,gs.combo);
                    }
                    // ── FIRST BLOOD ──
